import React, { useEffect, useState } from 'react';
import { Modal, Form, Input, Button, message, Select, DatePicker } from 'antd';
import { UserOutlined, PhoneOutlined, MailOutlined, CarOutlined, HomeOutlined, NumberOutlined, GiftOutlined } from '@ant-design/icons';
import { useGetAllParkingLotsQuery } from '../api/app_parkinglot/apiParkinglot';
import { useRegisterMemberMutation } from '../api/app_member/apiMember';
import { useGetCurrentUserQuery } from '../api/app_home/apiAuth';
import { useGetParkingPlansByLotIdQuery } from '../api/app_parkingPlan/apiParkingPlan'; // Import query
import dayjs from 'dayjs';

const { Option } = Select;

interface MemberRequestModalProps {
    visible: boolean;
    onCancel: () => void;
    initialPlan?: string;
    initialPlanId?: number;
    initialParkingLotId?: number;
}

const MemberRequestModal: React.FC<MemberRequestModalProps> = ({ visible, onCancel, initialPlan, initialPlanId, initialParkingLotId }) => {
    const [form] = Form.useForm();
    const { data: parkingLotsData } = useGetAllParkingLotsQuery({});
    const [selectedLotId, setSelectedLotId] = useState<number | undefined>(initialParkingLotId); // Track selected lot

    // Fetch plans based on selected lot. Skip if no lot selected.
    const { data: parkingPlans = [] } = useGetParkingPlansByLotIdQuery(selectedLotId!, {
        skip: !selectedLotId
    });

    const [registerMember, { isLoading }] = useRegisterMemberMutation();
    const { data: userData } = useGetCurrentUserQuery();

    const parkingLots = Array.isArray(parkingLotsData) ? parkingLotsData : (parkingLotsData as any)?.data || [];
    const [lotVehicleOptions, setLotVehicleOptions] = useState<string[]>([]);

    useEffect(() => {
        if (selectedLotId && parkingLots.length > 0) {
            const lot = parkingLots.find((l: any) => l.id === selectedLotId);
            if (lot && lot.vehicleTypes) {
                // Parse vehicleTypes string (e.g. "[Car, Moto]" or "Car, Moto") into options
                let types = lot.vehicleTypes;
                if (typeof types === 'string') {
                    types = types.replace(/[\[\]]/g, '').split(',');
                }
                if (Array.isArray(types)) {
                    setLotVehicleOptions(types.map((t: string) => t.trim()));
                }
            } else {
                setLotVehicleOptions([]);
            }
        } else {
            setLotVehicleOptions([]);
        }
    }, [selectedLotId, parkingLots]);

    useEffect(() => {
        if (visible && userData?.data) {
            form.resetFields();

            const user = userData.data;
            // Pre-fill form with user data if available
            form.setFieldsValue({
                fullname: user.fullname || '',
                phoneNumber: user.phoneNumber || '',
                email: user.email || '',
                dateOfBirth: user.dateOfBirth ? dayjs(user.dateOfBirth) : null,
                parkingLotId: initialParkingLotId || undefined,
                planId: initialPlanId || undefined // Pre-select plan if passed
            });
            if (initialParkingLotId) {
                setSelectedLotId(initialParkingLotId);
            }
        }
    }, [visible, userData, form, initialParkingLotId, initialPlanId]);

    const handleLotChange = (value: number) => {
        setSelectedLotId(value);
        form.setFieldsValue({
            planId: undefined,
            vehicleType: undefined
        }); // Reset plan and vehicle type when lot changes
    };

    const onFinish = async (values: any) => {
        if (!userData?.data?.id) {
            message.error('Vui lòng đăng nhập để thực hiện chức năng này!');
            return;
        }

        try {
            const payload = {
                parkingLotId: values.parkingLotId,
                planId: values.planId, // Use selected plan ID from form
                licensePlate: values.licensePlate,
                vehicleType: values.vehicleType,
                dateOfBirth: values.dateOfBirth ? values.dateOfBirth.format('YYYY-MM-DD') : null,
                address: values.address,
                phoneNumber: values.phoneNumber,
                email: values.email,
                fullname: values.fullname,
                roomNumber: values.roomNumber
            };

            await registerMember({
                userId: userData.data.id,
                data: payload
            }).unwrap();

            message.success('Gửi yêu cầu đăng ký thành công! Chúng tôi sẽ liên hệ lại sớm nhất.');
            onCancel();
        } catch (error) {
            console.error(error);
            message.error('Gửi yêu cầu thất bại. Vui lòng thử lại!');
        }
    };

    return (
        <Modal
            title={
                <div className="text-center mb-6">
                    <h3 className="text-2xl font-bold text-slate-900">Đăng Ký Gói Thành Viên</h3>
                </div>
            }
            open={visible}
            onCancel={onCancel}
            footer={null}
            centered
            destroyOnClose
            width={800}
        >
            <Form
                form={form}
                layout="vertical"
                onFinish={onFinish}
                className="mt-4"
                initialValues={{
                    planId: initialPlanId
                }}
            >
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <Form.Item
                        name="fullname"
                        label="Họ và Tên"
                        rules={[{ required: true, message: 'Vui lòng nhập họ tên!' }]}
                    >
                        <Input prefix={<UserOutlined className="text-gray-400" />} placeholder="Nguyễn Văn A" />
                    </Form.Item>

                    <Form.Item
                        name="dateOfBirth"
                        label="Ngày Sinh"
                        rules={[{ required: true, message: 'Vui lòng chọn ngày sinh!' }]}
                    >
                        <DatePicker style={{ width: '100%' }} format="DD/MM/YYYY" placeholder="Chọn ngày sinh" />
                    </Form.Item>

                    <Form.Item
                        name="phoneNumber"
                        label="Số Điện Thoại"
                        rules={[
                            { required: true, message: 'Vui lòng nhập số điện thoại!' },
                            { pattern: /^[0-9]{10}$/, message: 'Số điện thoại không hợp lệ!' }
                        ]}
                    >
                        <Input prefix={<PhoneOutlined className="text-gray-400" />} placeholder="0901234567" />
                    </Form.Item>

                    <Form.Item
                        name="email"
                        label="Email"
                        rules={[
                            { required: true, message: 'Vui lòng nhập email!' },
                            { type: 'email', message: 'Email không hợp lệ!' }
                        ]}
                    >
                        <Input prefix={<MailOutlined className="text-gray-400" />} placeholder="example@email.com" />
                    </Form.Item>

                    <Form.Item
                        name="address"
                        label="Địa Chỉ"
                        rules={[{ required: true, message: 'Vui lòng nhập địa chỉ!' }]}
                        className="md:col-span-2"
                    >
                        <Input prefix={<HomeOutlined className="text-gray-400" />} placeholder="123 Nguyễn Huệ, Phường Bến Nghé, Quận 1" />
                    </Form.Item>

                    <Form.Item
                        name="parkingLotId"
                        label="Bãi Đỗ Xe"
                        rules={[{ required: true, message: 'Vui lòng chọn bãi đỗ xe!' }]}
                    >
                        <Select placeholder="Chọn bãi đỗ xe" onChange={handleLotChange}>
                            {parkingLots.map((lot: any) => (
                                <Option key={lot.id} value={lot.id}>{lot.name}</Option>
                            ))}
                        </Select>
                    </Form.Item>

                    <Form.Item
                        name="planId"
                        label="Gói Dịch Vụ"
                        rules={[{ required: true, message: 'Vui lòng chọn gói dịch vụ!' }]}
                    >
                        <Select
                            placeholder="Chọn gói dịch vụ"
                            disabled={!selectedLotId}
                            suffixIcon={<GiftOutlined className="text-gray-400" />}
                        >
                            {(Array.isArray((parkingPlans as any)?.data) ? (parkingPlans as any).data : []).map((plan: any) => (
                                <Option key={plan.id} value={plan.id}>
                                    {plan.name} - {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(plan.price)}
                                    {plan.priceUnit === 'DAY' ? '/Ngày' : (plan.priceUnit === 'MONTH' ? '/Tháng' : '/Năm')}
                                </Option>
                            ))}
                        </Select>
                    </Form.Item>

                    <Form.Item
                        name="roomNumber"
                        label="Số Phòng (nếu có)"
                        rules={[{ required: true, message: 'Vui lòng nhập số phòng!' }]}
                    >
                        <Input prefix={<NumberOutlined className="text-gray-400" />} placeholder="C101" />
                    </Form.Item>

                    <Form.Item
                        name="vehicleType"
                        label="Loại Xe"
                        rules={[{ required: true, message: 'Vui lòng chọn loại xe!' }]}
                    >
                        <Select
                            placeholder="Chọn loại xe"
                            suffixIcon={<CarOutlined className="text-gray-400" />}
                            disabled={!selectedLotId}
                        >
                            {lotVehicleOptions.map((type) => (
                                <Option key={type} value={type}>{type}</Option>
                            ))}
                        </Select>
                    </Form.Item>

                    <Form.Item
                        name="licensePlate"
                        label="Biển Số Xe"
                        rules={[{ required: true, message: 'Vui lòng nhập biển số xe!' }]}
                    >
                        <Input placeholder="59A-12345" />
                    </Form.Item>
                </div>

                <Form.Item className="mb-0 text-center">
                    <Button
                        type="primary"
                        htmlType="submit"
                        loading={isLoading}
                        size="large"
                        className="bg-orange-500 hover:bg-orange-600 font-bold border-none h-12 shadow-lg min-w-[200px]"
                    >
                        GỬI YÊU CẦU ĐĂNG KÝ
                    </Button>
                </Form.Item>
            </Form>
        </Modal>
    );
};

export default MemberRequestModal;

import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import Sider from 'antd/es/layout/Sider';
import { Image, Menu, MenuProps } from 'antd';
import { CarOutlined, DashboardOutlined, BuildOutlined, TeamOutlined, AuditOutlined, GiftOutlined } from '@ant-design/icons';
import { useAuth } from '../../contexts/AuthContext';
export default function Navbar() {
    const location = useLocation();
    const [collapsed, setCollapsed] = useState(false);
    const { isAdmin } = useAuth();
    const menuItems: MenuProps['items'] = [
        {
            key: '/dashboard',
            icon: <DashboardOutlined />,
            label: <Link to="/dashboard">Dashboard</Link>,
        },
        {
            key: '/park-vehicle',
            icon: <CarOutlined />,
            label: <Link to="/park-vehicle">Gửi xe</Link>,
        },
        {
            key: '/parking-management',
            icon: <BuildOutlined />,
            label: <Link to="/parking-management">Quản lý bãi đỗ</Link>,
        },
        ...(!isAdmin ? [{
            key: '/timekeeping',
            icon: <AuditOutlined />,
            label: <Link to="/timekeeping">Chấm công nhân viên</Link>,
        }] : []),
        ...(isAdmin ? [{
            key: '/employee-management',
            icon: <TeamOutlined />,
            label: <Link to="/employee-management">Quản lý nhân viên</Link>,
        },
        {
            key: '/member-management',
            icon: <TeamOutlined />,
            label: <Link to="/member-management">Quản lý thành viên</Link>,
        },
        {
            key: '/invoice-management',
            icon: <AuditOutlined />,
            label: <Link to="/invoice-management">Quản lý hóa đơn</Link>,
        }] : []),
        {
            key: '/user',
            icon: <AuditOutlined />,
            label: <Link to="/user">Cá nhân</Link>,
        },
    ];

    return (
        <Sider
            className='shadow-lg bg-white  z-10'
            width={200}
            collapsible
            collapsed={collapsed}
            onCollapse={(value) => setCollapsed(value)}
            theme="light"
        >
            <div
                style={{
                    display: 'flex',
                    justifyContent: 'center',
                    alignItems: 'center',
                    height: '64px',
                    marginBottom: '16px',
                }}
            >
                <Image
                    src="/logopk.png"
                    alt="Logo"
                    preview={false}
                    width={collapsed ? 40 : 100}
                />
            </div>
            <Menu
                mode="inline"
                defaultSelectedKeys={['/']}
                selectedKeys={[location.pathname]}
                style={{ height: '100%', borderRight: 0 }}
                items={menuItems}
            />
        </Sider>
    );
}

import React, { useState } from 'react';
import { useGetPopularParkingPlansQuery } from '../api/app_parkingPlan/apiParkingPlan';
import { Spin, message } from 'antd';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { Check } from 'lucide-react';
import MemberRequestModal from './MemberRequestModal';

const ParkingRates: React.FC = () => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedPlan, setSelectedPlan] = useState<{ name: string, id: number } | { name: '', id: 0 }>({ name: '', id: 0 });
    const { isAuthenticated } = useAuth();
    const navigate = useNavigate();
    const { data: popularPlansData, isLoading } = useGetPopularParkingPlansQuery();

    const plansSource = (popularPlansData as any)?.data || popularPlansData || [];
    const plansToDisplay = Array.isArray(plansSource) ? plansSource.slice(0, 4) : [];
    const firstPopularIndex = plansToDisplay.findIndex((p: any) => p.isPopular);
    const plans = plansToDisplay.map((plan: any, index: number) => {
        const features = [];
        if (plan.isUnlimitedParking) features.push("Đỗ xe không giới hạn");
        if (plan.hasFixedSpot) features.push("Chỗ cố định");
        if (plan.hasValetService) features.push("Dịch vụ Valet");
        if (plan.hasCarWash) features.push("Rửa xe miễn phí");
        if (plan.hasCoveredParking) features.push("Có mái che");
        if (plan.hasSecurity247) features.push("An ninh 24/7");
        const isPopular = plan.isPopular && index === firstPopularIndex;

        return {
            id: plan.id,
            name: plan.name,
            price: new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(plan.price),
            period: plan.priceUnit === 'DAY' ? '/ ngày' : (plan.priceUnit === 'MONTH' ? '/ tháng' : '/ năm'),
            desc: plan.description,
            features: features,
            isPopular: index === 1
        };
    });

    if (isLoading) {
        return <div className="flex justify-center py-20"><Spin size="large" /></div>;
    }

    const handleOpenModal = (planName: string, planId: number) => {
        if (!isAuthenticated) {
            message.warning("Vui lòng đăng nhập để đăng ký thành viên!");
            navigate('/login');
            return;
        }
        setSelectedPlan({ name: planName, id: planId });
        setIsModalOpen(true);
    };

    return (
        <section className="py-20 bg-gray-50 font-sans">
            <div className="container mx-auto px-4 md:px-8">
                {/* Header */}
                <div className="text-center mb-16">
                    <span className="text-orange-500 font-bold uppercase tracking-widest text-sm">Bảng Giá Dịch Vụ</span>
                    <h2 className="text-3xl md:text-5xl font-extrabold text-slate-900 mt-3">
                        Gói Member & <br />
                        <span className="text-blue-600">
                            Tùy Chọn Đậu Xe
                        </span>
                    </h2>
                    <div className="w-24 h-1.5 bg-orange-500 mx-auto mt-6 rounded-full"></div>
                </div>

                {/* Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                    {plans.map((plan, idx) => (
                        <div
                            key={idx}
                            className={`relative bg-white rounded-xl overflow-hidden border-2 transition-all duration-300 hover:-translate-y-2 hover:shadow-xl flex flex-col
                                ${plan.isPopular ? 'border-orange-500 shadow-lg scale-105 z-10' : 'border-transparent hover:border-blue-200'}
                            `}
                        >
                            {plan.isPopular && (
                                <div className="bg-orange-500 text-white text-xs font-bold uppercase py-1 px-4 absolute top-0 right-0 rounded-bl-xl">
                                    Phổ Biến
                                </div>
                            )}

                            <div className="p-8 text-center border-b border-gray-100">
                                <div className="flex justify-center items-baseline text-slate-900 mb-2">
                                    <span className="text-2xl md:text-3xl font-extrabold text-blue-600">{plan.price}</span>
                                    <span className="text-gray-500 ml-1 text-sm">{plan.period}</span>
                                </div>
                                <h3 className="text-xl font-bold text-slate-900 mb-4">{plan.name}</h3>
                                <p className="text-gray-500 text-sm leading-relaxed mb-0">
                                    {plan.desc}
                                </p>
                            </div>

                            <div className="p-8 bg-white flex-grow flex flex-col justify-between">
                                <ul className="space-y-3 mb-8">
                                    {plan.features.map((feature, fIdx) => (
                                        <li key={fIdx} className="flex items-center text-sm text-gray-600">
                                            <div className="w-5 h-5 rounded-full bg-blue-50 text-blue-500 flex items-center justify-center mr-3 shrink-0">
                                                <Check size={12} strokeWidth={3} />
                                            </div>
                                            {feature}
                                        </li>
                                    ))}
                                </ul>

                                <button
                                    onClick={() => handleOpenModal(plan.name, plan.id)}
                                    className={`w-full py-3 rounded-lg font-bold uppercase text-sm tracking-wider transition-colors
                                    ${plan.isPopular
                                            ? 'bg-orange-500 text-white hover:bg-orange-600 shadow-md shadow-orange-500/20'
                                            : 'bg-slate-100 text-slate-600 hover:bg-slate-900 hover:text-white'}
                                `}>
                                    Đăng Ký Ngay
                                </button>
                            </div>

                            {!plan.isPopular && (
                                <div className="absolute inset-0 border-2 border-dashed border-gray-200 rounded-xl pointer-events-none"></div>
                            )}
                        </div>
                    ))}
                </div>
            </div>

            {/* Request Modal */}
            <MemberRequestModal
                visible={isModalOpen}
                onCancel={() => setIsModalOpen(false)}
                initialPlan={selectedPlan.name}
                initialPlanId={selectedPlan.id}
            />
        </section>
    );
};

export default ParkingRates;

import React, { useEffect } from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { getAccessTokenFromCookie } from '../utils/token';
import { Spin } from 'antd';

interface ProtectedRouteProps {
    children: React.ReactNode;
}

const ProtectedRoute: React.FC<ProtectedRouteProps> = ({ children }) => {
    const { isAuthenticated } = useAuth();
    const location = useLocation();
    const token = getAccessTokenFromCookie();
    if (!token) {
        return <Navigate to="/login" state={{ from: location }} replace />;
    }
    if (!isAuthenticated) {
        return <Spin />;
    }
    return <>{children}</>;
};

export default ProtectedRoute;

import React, { useState, useEffect } from "react";
import { Layout, Form, Input, Button, List, Card, Avatar, Typography, Tabs, message, DatePicker, Tag, Spin } from "antd";
import { UserOutlined, LockOutlined, CarOutlined, LogoutOutlined } from '@ant-design/icons';
import './UserInfo.css';
import { useChangePasswordMutation, useGetCurrentUserQuery, useUpdateUserInfoMutation } from "../../api/app_home/apiAuth";
import { getAccessTokenFromCookie } from "../../utils/token";
import dayjs from 'dayjs';
import { useAuth } from "../../contexts/AuthContext";

const { Content } = Layout;
const { Title, Text } = Typography;
const { TabPane } = Tabs;

const UserInfo = () => {
    const [form] = Form.useForm();
    const [isEdit, setIsEdit] = useState(false);
    const { logout } = useAuth();

    const handleEditToggle = () => {
        setIsEdit(true);
    };

    const handleLogout = () => {
        logout();
        message.success("Đăng xuất thành công!");
    };

    const { data: user, isLoading, error } = useGetCurrentUserQuery(undefined, {
        skip: !getAccessTokenFromCookie()
    });
    const [updateUserInfo] = useUpdateUserInfoMutation();
    const [changePassword] = useChangePasswordMutation();
    useEffect(() => {
        if (user?.data) {
            form.setFieldsValue({
                fullName: user.data.fullname,
                phoneNumber: user.data.phoneNumber,
                dateOfBirth: user.data.dateOfBirth ? dayjs(user.data.dateOfBirth) : null
            });
        }
    }, [user, form]);

    const handleUpdateUserInfo = async (values: any) => {
        await updateUserInfo(values);
        message.success("Cập nhật thông tin thành công!");
        setIsEdit(false);
    };

    const handleChangePassword = async (values: any) => {
        await changePassword(values);
        message.success("Cập nhật thông tin thành công!");
        setIsEdit(false);
    };

    if (isLoading) {
        return (
            <Layout className="userinfo-container">
                <Content style={{ padding: '24px', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
                    <Spin size="large" />
                </Content>
            </Layout>
        );
    }

    if (error) {
        return (
            <Layout className="userinfo-container">
                <Content style={{ padding: '24px' }}>
                    <Card>
                        <Typography.Text type="danger">Không thể tải thông tin người dùng. Vui lòng thử lại sau.</Typography.Text>
                    </Card>
                </Content>
            </Layout>
        );
    }

    return (
        <Layout className="userinfo-container">
            <Content style={{ padding: '24px' }}>
                <div className="userinfo-header" style={{ display: 'flex', alignItems: 'center', marginBottom: 24, justifyContent: 'space-between' }}>
                    <div style={{ display: 'flex', alignItems: 'center' }}>
                        <Avatar size={64} icon={<UserOutlined />} style={{ marginRight: 16 }} />
                        <div>
                            <Title level={4} style={{ margin: 0 }}>{user?.data?.fullname || 'Chưa cập nhật'}</Title>
                            <Text>Thông tin tài khoản</Text>
                        </div>
                    </div>
                    <Button
                        type="primary"
                        danger
                        icon={<LogoutOutlined />}
                        onClick={handleLogout}
                    >
                        Đăng Xuất
                    </Button>
                </div>

                <Card>
                    <Tabs defaultActiveKey="personalInfo" type="line" tabBarGutter={32}>
                        <TabPane tab="Thông Tin Cá Nhân" key="personalInfo">
                            <Form
                                layout="vertical"
                                form={form}
                                className="userinfo-form"
                                style={{ maxWidth: 500 }}
                                onFinish={handleUpdateUserInfo}
                            >
                                <Form.Item label="Tên Người Gửi" name="fullName" rules={[{ required: true }]}>
                                    <Input placeholder="Nhập tên người gửi" disabled={!isEdit} />
                                </Form.Item>

                                <Form.Item label="Số Điện Thoại" name="phoneNumber" rules={[{ required: true }]}>
                                    <Input placeholder="Nhập số điện thoại" disabled={!isEdit} />
                                </Form.Item>
                                <Form.Item label="Ngày Sinh" name="dateOfBirth" rules={[{ required: true }]}>
                                    <DatePicker placeholder="Nhập ngày sinh" disabled={!isEdit} />
                                </Form.Item>
                                <Form.Item>
                                    {isEdit ? (
                                        <Button htmlType="submit">Lưu</Button>
                                    ) : (
                                        ""
                                    )}
                                </Form.Item>
                                {!isEdit ? (
                                    <Button htmlType="button" onClick={handleEditToggle}>Sửa Đổi</Button>
                                ) : null}
                            </Form>
                        </TabPane>

                        <TabPane tab="Đổi Mật Khẩu" key="changePassword">
                            <Form layout="vertical" className="userinfo-form" style={{ maxWidth: 500 }} onFinish={handleChangePassword}>
                                <Form.Item label="Mật Khẩu Cũ" name="password">
                                    <Input.Password placeholder="Nhập mật khẩu cũ" />
                                </Form.Item>

                                <Form.Item label="Mật Khẩu Mới" name="newPassword">
                                    <Input.Password placeholder="Nhập mật khẩu mới" />
                                </Form.Item>
                                <Form.Item label="Nhập Lại Mật Khẩu Mới" name="retypePassword">
