    revenue: number;
}

interface RevenueData {
    date: string;
    amount: number;
    type: 'car' | 'motorbike';
}

const Dashboard: React.FC = () => {
    const [activeTab, setActiveTab] = useState('1');
    const { data: parkingLots = [], isLoading: isLoadingParkingLots } = useGetAllParkingLotsQuery({});

    const getTabTitle = (tabKey: string) => {
