            children: <OverviewTab parkingLots={parkingLots} isLoading={isLoadingParkingLots} />
        },
        {
            key: '2',
            label: 'Doanh thu',
            children: <RevenueTab parkingLots={parkingLots} isLoading={isLoadingParkingLots} />
        },
    ];

    return (
        <>
            <BreadcrumbDetail
                pageName="Dashboard"
                title={getTabTitle(activeTab)}
                pageLink="/"
            />
            <Tabs
                activeKey={activeTab}
                onChange={setActiveTab}
                items={items}
                size="large"
            />
        </>
    );
};

