import React from 'react';
import { Card, Row, Col, Statistic, Progress, Tag, Typography } from 'antd';
import {
    DollarOutlined,
    CarOutlined,
    UserOutlined,
    EnvironmentOutlined,
    CheckCircleOutlined,
    ClockCircleOutlined
} from '@ant-design/icons';
import { ParkingLot } from '../../../api/app_parkinglot/apiParkinglot';
import { useGetRevenueQuery } from '../../../api/app_revenue/apiRevenue';
import dayjs from 'dayjs';

const { Title, Text } = Typography;

interface OverviewTabProps {
    parkingLots: ParkingLot[];
    isLoading: boolean;
}

const OverviewTab: React.FC<OverviewTabProps> = ({ parkingLots, isLoading }) => {
    const today = dayjs().format('YYYY-MM-DD');
    const { data: revenueResponse, isLoading: isLoadingRevenue } = useGetRevenueQuery({
        startDate: today,
        endDate: today
    }, {
        refetchOnMountOrArgChange: true
    });
    if (isLoading && isLoadingRevenue) {
        return (
            <div className="p-4 flex items-center justify-center min-h-[200px]">
                <div className="text-center">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-500 mx-auto mb-2"></div>
                    <div>Đang tải dữ liệu...</div>
                </div>
            </div>
        );
    }
    console.log(revenueResponse);
    const totalRevenue = revenueResponse?.reduce((sum, record) =>
        sum + record.totalRevenue, 0) || 0;

    const totalSessions = revenueResponse?.reduce((sum, record) =>
        sum + record.totalSessions, 0) || 0;

    const totalParkingSpots = parkingLots.reduce((sum, lot) => sum + lot.capacity, 0);
    const availableSpots = parkingLots.reduce((sum, lot) => sum + lot.availableSlots, 0);
    const occupiedSpots = totalParkingSpots - availableSpots;

    const activeParkingLots = parkingLots.filter(lot => lot.status === 'ACTIVE').length;
    const inactiveParkingLots = parkingLots.length - activeParkingLots;

    const totalEmployees = parkingLots.reduce((sum, lot) =>
        sum + (lot.employeeDTOs ? lot.employeeDTOs.length : 0), 0
    );
    const utilizationPercent = totalParkingSpots > 0
        ? Math.round((occupiedSpots / totalParkingSpots) * 100)
        : 0;

    return (
        <div className="p-4">
            <Row gutter={[16, 16]} className="mb-6">
                <Col span={12}>
                    <Card className="h-full">
                        <Statistic
                            title="Tổng doanh thu ngày"
                            value={totalRevenue}
                            prefix={<DollarOutlined />}
                            suffix="VNĐ"
                            valueStyle={{ color: '#3f8600' }}
                            formatter={(value) => `${Number(value).toLocaleString('vi-VN')}`}
                        />
                        <div className="mt-4">
                            <Text type="secondary">Ngày: {today}</Text>
                            <div className="mt-2">
                                <Text type="secondary">Tổng lượt gửi xe:</Text>
                                <Text strong className="ml-2">{totalSessions}</Text>
                            </div>
                        </div>
                    </Card>
                </Col>

                <Col span={12}>
                    <Card className="h-full">
                        <div className="flex justify-between items-start">
                            <Statistic
                                title="Tổng số bãi xe"
                                value={parkingLots.length}
                                prefix={<EnvironmentOutlined />}
                                valueStyle={{ color: '#1890ff' }}
                            />
                            <div>
                                <Tag icon={<CheckCircleOutlined />} color="success">
                                    Đang hoạt động: {activeParkingLots}
                                </Tag>
                                <Tag icon={<ClockCircleOutlined />} color="warning" className="mt-2">
                                    Tạm dừng: {inactiveParkingLots}
                                </Tag>
                            </div>
                        </div>

                        <div className="mt-6">
                            <Text type="secondary">Nhân viên quản lý</Text>
                            <Title level={4} className="mt-1">
                                {totalEmployees} người
                            </Title>
                        </div>
                    </Card>
                </Col>
            </Row>

            {/* Parking Spots Section */}
            <Row gutter={[16, 16]} className="mb-6">
                <Col span={24}>
                    <Card title="Tình trạng chỗ đỗ xe">
                        <div className="flex items-center mb-4">
                            <Text strong className="mr-4">Tổng số chỗ đỗ:</Text>
                            <Text>{totalParkingSpots.toLocaleString('vi-VN')}</Text>
                            <div className="ml-auto flex">
                                <Tag color="green" className="mr-2">
                                    Còn trống: {availableSpots.toLocaleString('vi-VN')}
                                </Tag>
                                <Tag color="orange">
                                    Đã sử dụng: {occupiedSpots.toLocaleString('vi-VN')}
                                </Tag>
                            </div>
                        </div>

                        <Progress
                            percent={utilizationPercent}
                            status="active"
                            strokeColor={{
                                '0%': '#87d068',
                                '100%': '#ff5500',
                            }}
                        />

                        <div className="mt-6 grid grid-cols-3 gap-4">
                            {parkingLots.map(lot => (
                                <Card
                                    key={lot.id}
                                    size="small"
                                    title={<span className="font-bold">{lot.name}</span>}
                                    extra={<Tag color={lot.status === 'ACTIVE' ? 'green' : 'orange'}>{lot.status}</Tag>}
                                >
                                    <div className="flex justify-between">
                                        <div>
                                            <Text type="secondary">Sức chứa:</Text>
                                            <div>{lot.capacity}</div>
                                        </div>
                                        <div>
                                            <Text type="secondary">Còn trống:</Text>
                                            <div className={lot.availableSlots < 10 ? 'text-red-500' : 'text-green-500'}>
                                                {lot.availableSlots}
                                            </div>
                                        </div>
                                        <div>
                                            <Text type="secondary">Giá/giờ:</Text>
                                            <div>{lot.hourlyRate.toLocaleString('vi-VN')} VNĐ</div>
                                        </div>
                                    </div>
                                </Card>
                            ))}
                        </div>
                    </Card>
                </Col>
            </Row>
            <Row gutter={[16, 16]}>
                <Col span={24}>
                    <Card title="Loại phương tiện">
                        <div className="grid grid-cols-4 gap-4">
                            {parkingLots.map(lot => (
                                <Card key={lot.id} size="small">
                                    <div className="font-medium mb-2">{lot.name}</div>
                                    <div className="flex flex-wrap gap-2">
                                        {lot.vehicleTypes.split(',').map((type, idx) => (
                                            <Tag key={idx} color="blue">
                                                {type.trim()}
                                            </Tag>
                                        ))}
                                    </div>
                                </Card>
                            ))}
                        </div>
                    </Card>
                </Col>
            </Row>
        </div>
    );
};

export default OverviewTab;

import React, { useState, useEffect } from 'react';
import {
    Card,
    Row,
    Col,
    Statistic,
    Table,
    Tag,
    DatePicker,
    Typography,
    Spin,
    Button
} from 'antd';
import type { ColumnsType } from 'antd/es/table';
import {
    DollarOutlined,
    BarChartOutlined,
    PieChartOutlined,
    CarOutlined,
} from '@ant-design/icons';
import dayjs from 'dayjs';
import { BarChart, Bar, PieChart, Pie, Cell, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { useGetRevenueQuery } from '../../../api/app_revenue/apiRevenue';
import RevenueDetailModal from './RevenueDetailModal';
import { ParkingLot } from '../../../api/app_parkinglot/apiParkinglot';

const { Title, Text } = Typography;
const { RangePicker } = DatePicker;

interface RevenueTabProps {
    parkingLots: ParkingLot[];
    isLoading: boolean;
}

interface RevenueRecord {
    id: number;
    parkingLotId: number;
    parkingLotName: string;
    date: string;
    totalSessions: number;
    totalRevenue: number;
    averageDurationMinutes: number;
    details: {
        time: string;
        vehicleType: 'car' | 'motorbike';
        licensePlate: string;
        amount: number;
        duration: string;
    }[];
}

interface ParkingLotRevenue {
    id: number;
    name: string;
    totalRevenue: number;
    sessions: number;
    averageDuration: number;
    capacity: number;
    availableSlots: number;
    status: string;
    details: {
        time: string;
        vehicleType: 'car' | 'motorbike';
        licensePlate: string;
        amount: number;
        duration: string;
    }[];
}

const RevenueTab: React.FC<RevenueTabProps> = ({ parkingLots, isLoading: isLoadingParkingLots }) => {
    const [dateRange, setDateRange] = useState<[dayjs.Dayjs, dayjs.Dayjs]>([
        dayjs().startOf('month'),
        dayjs().endOf('month')
    ]);
    const [selectedParkingLot, setSelectedParkingLot] = useState<number | null>(null);
    const [selectedParking, setSelectedParking] = useState<ParkingLotRevenue | null>(null);
    const [parkingLotRevenues, setParkingLotRevenues] = useState<ParkingLotRevenue[]>([]);
    const [revenueChartData, setRevenueChartData] = useState<any[]>([]);
    const [vehicleTypeData, setVehicleTypeData] = useState<any[]>([]);
    const [selectedDate, setSelectedDate] = useState<string | null>(null);
    const [revenueDetails, setRevenueDetails] = useState<RevenueRecord[]>([]);
    const [detailModalVisible, setDetailModalVisible] = useState(false);

    const { data: revenueResponse, isLoading: isLoadingRevenue, isError } = useGetRevenueQuery({
        startDate: dateRange[0].format('YYYY-MM-DD'),
        endDate: dateRange[1].format('YYYY-MM-DD'),
        ...(selectedParkingLot && { parkingLotId: selectedParkingLot })
    });

    useEffect(() => {
        if (revenueResponse && parkingLots.length > 0) {
            const combinedRevenues = parkingLots.map(lot => {
                const revenueData = Array.isArray(revenueResponse)
                    ? revenueResponse.filter(r => r.parkingLotId === lot.id)
                    : [];
                const totalRevenue = revenueData.reduce((sum, r) => sum + r.totalRevenue, 0);
                const totalSessions = revenueData.reduce((sum, r) => sum + r.totalSessions, 0);
                const totalDuration = revenueData.reduce((sum, r) => sum + r.averageDurationMinutes, 0);
                const averageDuration = revenueData.length > 0 ? totalDuration / revenueData.length : 0;

                const allDetails = revenueData.flatMap(r => {
                    const date = r.date;
                    return (r.details || []).map(detail => ({
                        ...detail,
                        time: `${date} ${detail.time}`
                    }));
                });

                return {
                    id: lot.id,
                    name: lot.name,
                    totalRevenue,
                    sessions: totalSessions,
                    averageDuration: Math.round(averageDuration),
                    capacity: lot.capacity,
                    availableSlots: lot.availableSlots,
                    status: lot.status,
                    details: allDetails
                };
            });

            setParkingLotRevenues(combinedRevenues);
            const chartData = combinedRevenues.map(lot => ({
                name: lot.name,
                revenue: lot.totalRevenue,
                sessions: lot.sessions
            }));
            setRevenueChartData(chartData);

            // Tính toán số lượt gửi theo loại xe (70% ô tô, 30% xe máy)
            const vehicleTypes = [
                { type: 'Ô tô', value: combinedRevenues.reduce((sum, lot) => sum + Math.round(lot.sessions * 0.7), 0) },
                { type: 'Xe máy', value: combinedRevenues.reduce((sum, lot) => sum + Math.round(lot.sessions * 0.3), 0) }
            ];
            setVehicleTypeData(vehicleTypes);
        }
    }, [revenueResponse, parkingLots]);

    const columns: ColumnsType<ParkingLotRevenue> = [
        {
            title: 'Tên bãi đỗ',
            dataIndex: 'name',
            key: 'name',
        },
        {
            title: 'Trạng thái',
            dataIndex: 'status',
            key: 'status',
            render: (status) => (
                <Tag color={status === 'ACTIVE' ? 'green' : 'orange'}>
                    {status === 'ACTIVE' ? 'Đang hoạt động' : 'Tạm dừng'}
                </Tag>
            ),
        },
        {
            title: 'Sức chứa',
            dataIndex: 'capacity',
            key: 'capacity',
            render: (capacity, record) => (
                <div>
                    <div>Tổng: {capacity}</div>
                    <div className={record.availableSlots < 10 ? 'text-red-500' : 'text-green-500'}>
                        Còn trống: {record.availableSlots}
                    </div>
                </div>
            ),
        },
        {
            title: 'Tổng doanh thu',
            dataIndex: 'totalRevenue',
            key: 'totalRevenue',
            render: (value) => `${value.toLocaleString('vi-VN')} VNĐ`,
            sorter: (a, b) => a.totalRevenue - b.totalRevenue,
        },
        {
            title: 'Số lượt gửi',
            dataIndex: 'sessions',
            key: 'sessions',
            sorter: (a, b) => a.sessions - b.sessions,
        },
        {
            title: 'Thời gian TB',
            dataIndex: 'averageDuration',
            key: 'averageDuration',
            render: (value) => `${value} phút`,
            sorter: (a, b) => a.averageDuration - b.averageDuration,
        },
        {
            title: 'Chi tiết',
            key: 'action',
            render: (_, record) => (
                <Button type="link" onClick={() => handleViewDetails(record.id, record.name)} className="p-0">
                    Xem chi tiết
                </Button>
            ),
        }
    ];

    const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042'];

    const CustomTooltip = ({ active, payload, label }: any) => {
        if (active && payload && payload.length) {
            return (
                <div className="bg-white p-2 border border-gray-200 shadow-md">
                    <p className="font-medium">{label}</p>
                    <p className="text-blue-500">
                        {payload[0].value.toLocaleString('vi-VN')} VNĐ
                    </p>
                </div>
            );
        }
        return null;
    };

    const handleDateRangeChange = (dates: any) => {
        if (dates) {
            setDateRange([dates[0], dates[1]]);
        }
    };

    const handleViewDetails = (parkingLotId: number, parkingLotName: string) => {
        const selectedRevenues = revenueResponse?.filter(r => r.parkingLotId === parkingLotId) || [];
        if (selectedRevenues.length > 0) {
            setSelectedParkingLot(parkingLotId);
            setSelectedDate(selectedRevenues[0].date);
            setRevenueDetails(selectedRevenues);
            setDetailModalVisible(true);
        }
    };

    const totalRevenue = parkingLotRevenues.reduce((sum, lot) => sum + lot.totalRevenue, 0);
    const totalSessions = parkingLotRevenues.reduce((sum, lot) => sum + lot.sessions, 0);

    if (isError) return <div>Đã xảy ra lỗi khi tải dữ liệu</div>;

    return (
        <div className="p-4">
            <div className="flex justify-between items-center mb-6">
                <Title level={3} className="!mb-0">Quản lý Doanh thu</Title>
                <div className="flex items-center gap-4">
                    <RangePicker
                        value={dateRange}
                        onChange={handleDateRangeChange}
                        format="DD/MM/YYYY"
                        className="w-80"
                    />
                </div>
            </div>

            <Spin spinning={isLoadingParkingLots || isLoadingRevenue}>
                <Row gutter={[16, 16]} className="mb-6">
                    <Col span={8}>
                        <Card className="h-full shadow-md">
                            <Statistic
                                title="Tổng doanh thu"
                                value={totalRevenue}
                                prefix={<DollarOutlined />}
                                formatter={(value) => `${Number(value).toLocaleString('vi-VN')} VNĐ`}
                                valueStyle={{ color: '#3f8600', fontSize: '24px' }}
                            />
                            <div className="mt-4">
                                <Text type="secondary">Trung bình mỗi lượt:</Text>
                                <Text strong className="block text-lg">
                                    {totalRevenue > 0 ? (totalRevenue / totalSessions).toLocaleString('vi-VN') : 0} VNĐ
                                </Text>
                            </div>
                        </Card>
                    </Col>

                    <Col span={8}>
                        <Card className="h-full shadow-md">
                            <Statistic
                                title="Tổng lượt gửi xe"
                                value={totalSessions}
                                prefix={<CarOutlined />}
                                valueStyle={{ fontSize: '24px' }}
                            />
                            <div className="mt-4 flex justify-between">
                                <div>
                                    <Text type="secondary">Ô tô:</Text>
                                    <Text strong className="block">{(totalSessions * 0.7).toFixed(0)}</Text>
                                </div>
                                <div>
                                    <Text type="secondary">Xe máy:</Text>
                                    <Text strong className="block">{(totalSessions * 0.3).toFixed(0)}</Text>
                                </div>
                            </div>
                        </Card>
                    </Col>

                    <Col span={8}>
                        <Card className="h-full shadow-md">
                            <div className="flex items-center h-full">
                                <PieChartOutlined className="text-3xl mr-4 text-blue-500" />
                                <div>
                                    <Text type="secondary">Thời gian gửi trung bình</Text>
                                    <Title level={3} className="!mt-1 !mb-0">
                                        {parkingLotRevenues.length > 0
                                            ? (parkingLotRevenues.reduce((sum, lot) => sum + lot.averageDuration, 0) / parkingLotRevenues.length).toFixed(0)
                                            : 0} phút
                                    </Title>
                                </div>
                            </div>
                        </Card>
                    </Col>
                </Row>

                <Row gutter={[16, 16]} className="mb-6">
                    <Col span={12}>
                        <Card
                            title="Doanh thu theo bãi xe"
                            className="shadow-md"
                            extra={<BarChartOutlined className="text-blue-500" />}
                        >
                            <div style={{ width: '100%', height: 300 }}>
                                <ResponsiveContainer>
                                    <BarChart
                                        data={revenueChartData}
                                        margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
                                    >
                                        <CartesianGrid strokeDasharray="3 3" />
                                        <XAxis dataKey="name" />
                                        <YAxis />
                                        <Tooltip content={<CustomTooltip />} />
                                        <Legend />
                                        <Bar dataKey="revenue" name="Doanh thu" fill="#1890ff" />
                                    </BarChart>
                                </ResponsiveContainer>
                            </div>
                        </Card>
                    </Col>
                    <Col span={12}>
                        <Card
                            title="Phân loại phương tiện"
                            className="shadow-md"
                            extra={<PieChartOutlined className="text-blue-500" />}
                        >
                            <div style={{ width: '100%', height: 300 }}>
                                <ResponsiveContainer>
                                    <PieChart>
                                        <Pie
                                            data={vehicleTypeData}
                                            cx="50%"
                                            cy="50%"
                                            labelLine={false}
                                            label={({ name, percent }) => `${name}: ${(percent * 100).toFixed(0)}%`}
                                            outerRadius={80}
                                            fill="#8884d8"
                                            dataKey="value"
                                            nameKey="type"
                                        >
                                            {vehicleTypeData.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                            ))}
                                        </Pie>
                                        <Tooltip formatter={(value: number) => `${value.toLocaleString('vi-VN')} lượt`} />
                                        <Legend />
                                    </PieChart>
                                </ResponsiveContainer>
                            </div>
                        </Card>
                    </Col>
                </Row>

                <Card
                    title="Chi tiết doanh thu"
                    className="shadow-md"
                    extra={<Text strong>
                        {dateRange[0].format('DD/MM/YYYY')} - {dateRange[1].format('DD/MM/YYYY')}
                    </Text>}
                >
                    <Table
                        columns={columns}
                        dataSource={parkingLotRevenues}
                        rowKey="id"
                        pagination={{ pageSize: 5 }}
                    />
                </Card>
            </Spin>

            <RevenueDetailModal
                visible={detailModalVisible}
                onClose={() => {
                    setDetailModalVisible(false);
                    setSelectedParkingLot(null);
                }}
                parkingLotName={selectedParking?.name || ''}
                date={selectedDate || ''}
                details={revenueDetails}
            />
        </div>
    );
};

export default RevenueTab;

import React, { useState, useEffect } from 'react';
import { Form, message, Tabs } from 'antd';
import {
    useGetAllEmployeesQuery,
    useCreateEmployeeMutation,
    useUpdateEmployeeMutation,
    useDeleteEmployeeMutation,
    Employee,
    CreateEmployeeRequest,
    UpdateEmployeeRequest,
} from '../../api/app_employee/apiEmployee';
import {
    useGetEmployeeShiftsQuery,
    useCreateEmployeeShiftsMutation,
    useUpdateEmployeeShiftMutation,
    useDeleteEmployeeShiftMutation,
    EmployeeShifts,
    CreateEmployeeShiftsRequest,
} from '../../api/app_employee/apiEmployeeShifts';
import { useGetAllShiftsQuery } from '../../api/app_employee/apiShifts';
import { useGetAllParkingLotsQuery } from '../../api/app_parkinglot/apiParkinglot';
import EmployeeManageView from './components/EmployeeManageView';
import EmployeeShiftsView from './components/EmployeeShiftsView';
import BreadcrumbFunction from '../../components/Breadcrumb/BreadcrumbFunction';
import dayjs from 'dayjs';
import { useDebounce } from '../../hooks/useDebounce';

const EmployeeManage: React.FC = () => {
    // Employee management states
    const [searchText, setSearchText] = useState('');
    const [isModalVisible, setIsModalVisible] = useState(false);
    const [isViewModalVisible, setIsViewModalVisible] = useState(false);
    const [form] = Form.useForm();
    const [selectedEmployee, setSelectedEmployee] = useState<Employee | null>(null);
    const [editingMode, setEditingMode] = useState<'create' | 'edit'>('create');
    const debouncedSearchText = useDebounce(searchText, 500);
    const [selectedShift, setSelectedShift] = useState<EmployeeShifts | null>(null);
    const [isShiftModalVisible, setIsShiftModalVisible] = useState(false);
    const [shiftForm] = Form.useForm();
    const [shiftEditingMode, setShiftEditingMode] = useState<'create' | 'edit'>('create');
    const [selectedDate, setSelectedDate] = useState<string>(dayjs().format('YYYY-MM-DD'));
    const [selectedShiftId, setSelectedShiftId] = useState<number | null>(null);

    const { data: employees, isLoading, refetch } = useGetAllEmployeesQuery(debouncedSearchText);
    const { data: employeeShifts, isLoading: isLoadingShifts, refetch: refetchShifts } = useGetEmployeeShiftsQuery({
        workDate: selectedDate || undefined,
        shiftId: selectedShiftId || undefined
    });
    const { data: shifts } = useGetAllShiftsQuery('');
    const { data: parkingLots } = useGetAllParkingLotsQuery({});
    const [createEmployee] = useCreateEmployeeMutation();
    const [updateEmployee] = useUpdateEmployeeMutation();
    const [deleteEmployee] = useDeleteEmployeeMutation();
    const [createEmployeeShift] = useCreateEmployeeShiftsMutation();
    const [updateEmployeeShift] = useUpdateEmployeeShiftMutation();
    const [deleteEmployeeShift] = useDeleteEmployeeShiftMutation();

    const handleSearch = (value: string) => {
        setSearchText(value);
    };

    const handleModalOpen = (mode: 'create' | 'edit', employee?: Employee) => {
        setEditingMode(mode);
        if (mode === 'edit' && employee) {
            setSelectedEmployee(employee);
            form.setFieldsValue({
                parkingLotId: employee.parkingLotId,
                userDTO: {
                    username: employee.userResponse.username,
                    fullname: employee.userResponse.fullname,
                    email: employee.userResponse.email,
                    phoneNumber: employee.userResponse.phoneNumber,
                    dateOfBirth: dayjs(employee.userResponse.dateOfBirth),
                },
                status: employee.status,
            });
        } else {
            form.resetFields();
            setSelectedEmployee(null);
        }
        setIsModalVisible(true);
    };

    const handleModalClose = () => {
        form.resetFields();
        setSelectedEmployee(null);
        setIsModalVisible(false);
    };

    const handleViewModalOpen = (employee: Employee) => {
        setSelectedEmployee(employee);
        setIsViewModalVisible(true);
    };

    const handleViewModalClose = () => {
        setSelectedEmployee(null);
        setIsViewModalVisible(false);
    };

    const handleSubmit = async (values: any) => {
        try {
            const userDtoPayload = {
                ...values.userDTO,
                fullName: values.userDTO.fullName || values.userDTO.fullname,
                dateOfBirth: values.userDTO.dateOfBirth.format('YYYY-MM-DD'),
            };

            let formattedValues: any;

            if (editingMode === 'create') {
                const selectedParkingLot = parkingLots?.find(p => p.id === values.parkingLotId);
                formattedValues = {
                    ...values,
                    parkingLotId: values.parkingLotId,
                    parkingLotName: selectedParkingLot?.name || '',
                    userDTO: userDtoPayload, // Use userDTO for creation
                    joinDate: new Date().toISOString(),
                    status: "ACTIVE", // Default status
                };
                await createEmployee(formattedValues as CreateEmployeeRequest).unwrap();
                message.success('Tạo nhân viên thành công!');
            } else { // editingMode === 'edit'
                if (selectedEmployee) {
                    formattedValues = {
                        ...values,
                        parkingLotId: values.parkingLotId, // Keep existing parkingLotId for edit
                        updateUserDTO: userDtoPayload, // Use updateUserDTO for update
                        joinDate: new Date().toISOString(), // Keep joinDate as per original logic, if API expects it
                    };
                    await updateEmployee({
                        id: selectedEmployee.id,
                        data: formattedValues as UpdateEmployeeRequest,
                    }).unwrap();
                    message.success('Cập nhật nhân viên thành công!');
                    refetch();
                }
            }
            handleModalClose();
        } catch (error: any) {
            if (error?.data?.message) {
                message.error(error.data.message);
            } else {
                message.error('Có lỗi xảy ra!');
            }
        }
    };

    const handleDelete = async (id: string) => {
        try {
            await deleteEmployee(id).unwrap();
            message.success('Xóa nhân viên thành công!');
            refetch();
        } catch (error) {
            message.error('Có lỗi xảy ra khi xóa nhân viên!');
        }
    };

    // Employee shifts handlers
    const handleShiftModalOpen = (mode: 'create' | 'edit', shift?: EmployeeShifts) => {
        setShiftEditingMode(mode);
        if (mode === 'edit' && shift) {
            setSelectedShift(shift);
            shiftForm.setFieldsValue({
                ...shift,
                workDate: dayjs(shift.workDate),
            });
        } else {
            shiftForm.resetFields();
            setSelectedShift(null);
        }
        setIsShiftModalVisible(true);
    };

    const handleShiftModalClose = () => {
        shiftForm.resetFields();
        setSelectedShift(null);
        setIsShiftModalVisible(false);
    };

    const handleShiftSubmit = async (values: any): Promise<EmployeeShifts> => {
        try {
            const selectedEmployee = employees?.find(emp => emp.id === values.employeeId);
            const selectedShift = shifts?.find(shift => shift.id === values.shiftId);
            const selectedParkingLot = parkingLots?.find(parkingLot => parkingLot.id === values.parkingLotId);
            const workDate = values.workDate.format('YYYY-MM-DD');

            if (shiftEditingMode === 'create') {
                const createRequest: CreateEmployeeShiftsRequest = {
                    employeeId: values.employeeId,
                    employeeName: selectedEmployee?.userResponse.fullname || '',
                    shiftId: values.shiftId.toString(),
                    shiftName: selectedShift?.shiftName || '',
                    shiftType: selectedShift?.shiftName || '',
                    shiftTime: `${selectedShift?.startTime} - ${selectedShift?.endTime}`,
                    workDate: workDate,
                    dayOfWeek: values.workDate.format('dddd').toUpperCase(),
                    isRecurring: values.isRecurring,
                    status: "SCHEDULED",
                    parkingLotId: values.parkingLotId
                };

                const response = await createEmployeeShift(createRequest).unwrap();
                message.success('Tạo ca làm việc thành công!');
                refetchShifts();
                return response as unknown as EmployeeShifts;
            } else {
                const updateRequest: EmployeeShifts = {
                    id: Number(values.employeeId),
                    employeeId: values.employeeId,
                    employeeName: selectedEmployee?.userResponse.fullname || '',
                    shiftId: values.shiftId,
                    shiftName: selectedShift?.shiftName || '',
                    shiftTime: `${selectedShift?.startTime} - ${selectedShift?.endTime}`,
                    workDate: workDate,
                    dayOfWeek: values.workDate.format('dddd').toUpperCase(),
                    isRecurring: values.isRecurring,
                    status: values.status,
                    parkingLotId: values.parkingLotId,
                    parkingLotName: selectedParkingLot?.name || ''
                };

                if (selectedShift) {
                    await updateEmployeeShift({
                        id: Number(values.employeeId),
                        data: updateRequest,
                    }).unwrap();
                    message.success('Cập nhật ca làm việc thành công!');
                    refetchShifts();
                    return updateRequest;
                }
            }
            handleShiftModalClose();
            throw new Error('Không thể xử lý yêu cầu');
        } catch (error: any) {
            if (error?.data?.message?.includes('Employee shift already exists')) {
                message.error('Nhân viên đã có ca làm việc này trong ngày');
            } else if (error?.data?.message) {
                message.error(error.data.message);
            } else {
                message.error('Có lỗi xảy ra!');
            }
            throw error;
        }
    };

    const handleShiftDelete = async (id: number) => {
        try {
            await deleteEmployeeShift({ id }).unwrap();
            message.success('Xóa ca làm việc thành công!');
            refetchShifts();
        } catch (error) {
            message.error('Có lỗi xảy ra khi xóa ca làm việc!');
        }
    };

    const handleDateChange = (date: string) => {
        setSelectedDate(date);
    };

    const handleShiftChange = (shiftId: number | null) => {
        setSelectedShiftId(shiftId);
    };

    // Add useEffect to handle refetch when filters change
    useEffect(() => {
        refetchShifts();
    }, [selectedDate, selectedShiftId]);

    const items = [
        {
            key: '1',
            label: 'Quản lý nhân viên',
            children: (
                <EmployeeManageView
                    employees={employees}
                    employeeShifts={employeeShifts}
                    isLoading={isLoading}
                    searchText={searchText}
                    isModalVisible={isModalVisible}
                    isViewModalVisible={isViewModalVisible}
                    editingMode={editingMode}
                    selectedEmployee={selectedEmployee}
                    form={form}
                    onSearch={handleSearch}
                    onModalOpen={handleModalOpen}
                    onModalClose={handleModalClose}
                    onViewModalOpen={handleViewModalOpen}
                    onViewModalClose={handleViewModalClose}
                    onSubmit={handleSubmit}
                    onDelete={handleDelete}
                />
            ),
        },
        {
            key: '2',
            label: 'Quản lý ca làm việc',
            children: (
                <EmployeeShiftsView
                    isLoading={isLoadingShifts}
                    isModalVisible={isShiftModalVisible}
                    editingMode={shiftEditingMode}
                    form={shiftForm}
                    onModalOpen={handleShiftModalOpen}
                    onModalClose={handleShiftModalClose}
                    onSubmit={handleShiftSubmit}
                    onDelete={handleShiftDelete}
                    onDateChange={handleDateChange}
                    onShiftChange={handleShiftChange}
                    selectedDate={selectedDate}
                    selectedShiftId={selectedShiftId}
                    dataSource={employeeShifts}
                />
            ),
        },
    ];

    return (
        <>
            <BreadcrumbFunction functionName="Quản lý nhân viên" title="Quản lý nhân viên" />
            <Tabs defaultActiveKey="1" items={items} />
        </>
    );
};

export default EmployeeManage;

import React, { useState } from 'react';
import { Table, Tag, DatePicker, Space } from 'antd';
import { Attendance, useGetAttendancesByEmployeeIdQuery } from '../../../api/app_employee/apiAttendance';
import dayjs from 'dayjs';

interface EmployeeAttendanceTableProps {
    employeeId: string;
}

const EmployeeAttendanceTable: React.FC<EmployeeAttendanceTableProps> = ({
    employeeId
}) => {
    const [startDate, setStartDate] = useState(dayjs().subtract(7, 'day'));
    const [endDate, setEndDate] = useState(dayjs());

    const { data: attendances, isLoading } = useGetAttendancesByEmployeeIdQuery({
        employeeId,
        startDate: startDate.format('YYYY-MM-DD'),
        endDate: endDate.format('YYYY-MM-DD')
    });

    const columns = [
        {
            title: 'Ngày',
            dataIndex: 'checkInTime',
            key: 'date',
            render: (time: string) => dayjs(time).format('DD/MM/YYYY'),
        },
        {
            title: 'Giờ check-in',
            dataIndex: 'checkInTime',
            key: 'checkInTime',
            render: (time: string) => time ? dayjs(time).format('HH:mm:ss') : '-',
        },
        {
            title: 'Giờ check-out',
            dataIndex: 'checkOutTime',
            key: 'checkOutTime',
            render: (time: string) => time ? dayjs(time).format('HH:mm:ss') : '-',
        },
        {
            title: 'Trạng thái',
            dataIndex: 'status',
            key: 'status',
            render: (status: string) => {
                const getStatusColor = (status: string) => {
                    switch (status) {
                        case 'PRESENT':
                            return 'success';
                        case 'ABSENT':
                            return 'error';
                        case 'LATE':
                            return 'warning';
                        case 'EARLY':
                            return 'warning';
                        default:
                            return 'default';
                    }
                };

                const getStatusText = (status: string) => {
                    switch (status) {
                        case 'PRESENT':
                            return 'Có mặt';
                        case 'ABSENT':
                            return 'Vắng mặt';
                        case 'LATE':
                            return 'Đi muộn';
                        case 'EARLY':
                            return 'Về Sớm';
                        default:
                            return status;
                    }
                };

                return (
                    <Tag color={getStatusColor(status)}>
                        {getStatusText(status)}
                    </Tag>
                );
            },
        },
    ];

    return (
        <div>
            <Space style={{ marginBottom: 16 }}>
                <DatePicker
                    value={startDate}
                    onChange={(date) => date && setStartDate(date)}
                    format="DD/MM/YYYY"
                />
                <DatePicker
                    value={endDate}
                    onChange={(date) => date && setEndDate(date)}
                    format="DD/MM/YYYY"
                />
            </Space>
            <Table
                columns={columns}
                dataSource={attendances}
                rowKey="id"
                pagination={{ pageSize: 5 }}
                scroll={{ y: 300 }}
                loading={isLoading}
            />
        </div>
    );
};

