    isModalVisible,
    selectedEmployee,
    employeeShifts,
    employeeAttendances,
    onClose,
    onEdit,
}) => {
    if (!selectedEmployee) return null;

    const filteredShifts = employeeShifts?.filter(
        shift => Number(shift.employeeId) === Number(selectedEmployee.id)
    );

    const filteredAttendances = employeeAttendances?.filter(
