import React, { useState, useMemo } from 'react';
import { Table, Tag, Button, Input, Tabs, Card } from 'antd';
import { SearchOutlined, EyeOutlined } from '@ant-design/icons';
import dayjs from 'dayjs';
import { useGetAllInvoicesQuery, useGetInvoicesByStatusQuery } from '../../api/app_invoice/apiInvoice';
import InvoiceDetailModal from './components/InvoiceDetailModal';

const InvoiceList: React.FC<{ status: string; onViewDetail: (invoice: any) => void }> = ({ status, onViewDetail }) => {
    const { data: allInvoices, isLoading: isAllLoading } = useGetAllInvoicesQuery(undefined, { skip: status !== 'ALL' });
    const { data: statusInvoices, isLoading: isStatusLoading } = useGetInvoicesByStatusQuery(status, { skip: status === 'ALL' });

    const invoices = status === 'ALL' ? allInvoices : statusInvoices;
    const isLoading = status === 'ALL' ? isAllLoading : isStatusLoading;

    const [searchText, setSearchText] = useState('');

    const dataSource = useMemo(() => {
        if (Array.isArray(invoices)) return invoices;
        if (invoices && typeof invoices === 'object' && Array.isArray((invoices as any).data)) return (invoices as any).data;
        return [];
    }, [invoices]);

    const columns = [
        {
            title: 'Mã Hóa Đơn',
            dataIndex: 'invoiceCode',
            key: 'invoiceCode',
            render: (text: string) => <span className="font-mono font-bold">{text}</span>,
            filteredValue: [searchText],
            onFilter: (value: any, record: any) =>
                record.invoiceCode?.toLowerCase().includes(value.toLowerCase()) ||
                record.memberId?.toString().includes(value),
        },
        {
            title: 'Loại',
            dataIndex: 'type',
            key: 'type',
            render: (type: string) => (
                <Tag color={type === 'MEMBERSHIP' ? 'blue' : 'orange'}>
                    {type === 'MEMBERSHIP' ? 'Đăng ký TV' : 'Phí gửi xe'}
                </Tag>
            ),
        },
        {
            title: 'Số Tiền',
            dataIndex: 'amount',
            key: 'amount',
            render: (amount: number) => (
                <span className="font-bold text-green-600">
                    {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(amount)}
                </span>
            ),
        },
        {
            title: 'Trạng Thái',
            dataIndex: 'status',
            key: 'status',
            render: (status: string) => {
                let color = 'default';
                let text = status;
                switch (status) {
                    case 'PAID': color = 'green'; text = 'Đã thanh toán'; break;
                    case 'UNPAID': color = 'orange'; text = 'Chưa thanh toán'; break;
                    case 'OVERDUE': color = 'red'; text = 'Quá hạn'; break;
                    case 'CANCELLED': color = 'gray'; text = 'Đã hủy'; break;
                }
                return <Tag color={color}>{text}</Tag>;
            },
        },
        {
            title: 'Ngày Tạo',
            dataIndex: 'createdAt',
            key: 'createdAt',
            render: (date: string) => dayjs(date).format('DD/MM/YYYY HH:mm'),
        },
        {
            title: 'Hành Động',
            key: 'action',
            render: (_: any, record: any) => (
                <Button
                    type="primary"
                    ghost
                    size="small"
                    icon={<EyeOutlined />}
                    onClick={(e) => {
                        e.stopPropagation();
                        onViewDetail(record);
                    }}
                >
                    Chi tiết
                </Button>
            ),
        },
    ];

    return (
        <div>
            <div className="mb-4 flex justify-between items-center">
                <Input
                    placeholder="Tìm kiếm theo mã hóa đơn..."
                    prefix={<SearchOutlined />}
                    className="w-64"
                    value={searchText}
                    onChange={(e) => setSearchText(e.target.value)}
                />
            </div>
            <Table
                columns={columns}
                dataSource={dataSource}
                rowKey="id"
                loading={isLoading}
                pagination={{ pageSize: 10 }}
                onRow={(record) => ({
                    onClick: () => onViewDetail(record),
                    style: { cursor: 'pointer' },
                })}
            />
        </div>
    );
};

const InvoiceManage: React.FC = () => {
    const [selectedInvoice, setSelectedInvoice] = useState<any | null>(null);
    const [isModalVisible, setIsModalVisible] = useState(false);

    const handleViewDetail = (invoice: any) => {
        setSelectedInvoice(invoice);
        setIsModalVisible(true);
    };

    const items = [
        { key: 'ALL', label: 'Tất cả hóa đơn', status: 'ALL' },
        { key: 'UNPAID', label: 'Chưa thanh toán', status: 'UNPAID' },
        { key: 'PAID', label: 'Đã thanh toán', status: 'PAID' },
        { key: 'OVERDUE', label: 'Quá hạn', status: 'OVERDUE' },
        { key: 'CANCELLED', label: 'Đã hủy', status: 'CANCELLED' },
    ];

    return (
        <div className="p-6">
            <h1 className="text-2xl font-bold mb-6 text-slate-800">Quản Lý Hóa Đơn</h1>

            <Tabs
                defaultActiveKey="ALL"
                type="card"
                items={items.map(item => ({
                    key: item.key,
                    label: item.label,
                    children: <InvoiceList status={item.status} onViewDetail={handleViewDetail} />
                }))}
            />

            <InvoiceDetailModal
                visible={isModalVisible}
                invoice={selectedInvoice}
                onClose={() => setIsModalVisible(false)}
            />
        </div>
    );
};

export default InvoiceManage;

import React, { useState } from 'react';
import { Table, Button, Tag, Space, message, Tooltip, Avatar } from 'antd';
import { useGetExpiringMembersQuery, useRenewMemberMutation } from '../../../api/app_member/apiMember';
import { ReloadOutlined, WarningOutlined, CarOutlined, UserOutlined } from '@ant-design/icons';
import ExpiringMemberDetailModal from './ExpiringMemberDetailModal';

const ExpiringMembersTab: React.FC = () => {
    // Replace 'any' with your actual type if available
    const { data: expiringMembersData, isLoading, refetch } = useGetExpiringMembersQuery();
    const [renewMember] = useRenewMemberMutation();

    const [viewMember, setViewMember] = useState<any | null>(null);
    const [isViewModalVisible, setIsViewModalVisible] = useState(false);

    const handleRenew = async (id: number) => {
        try {
            // Assuming renew accepts just ID or minimal data for now. 
            // Adjust payload if your API requires specific plan data for renewal
            await renewMember({ id }).unwrap();
            message.success('Đã gửi yêu cầu gia hạn thành công');
            refetch();
        } catch (error) {
            console.error(error);
            message.error('Gia hạn thất bại');
        }
    };

    const columns = [
        {
            title: 'Họ và tên',
            key: 'fullname',
            render: (_: any, record: any) => (
                <div className="flex items-center gap-2">
                    <Avatar icon={<UserOutlined />} src={record.avatar} size="small" />
                    <span className="font-medium">{record.fullname}</span>
                </div>
            )
        },
        {
            title: 'Mã thành viên',
            dataIndex: 'memberCode',
            key: 'memberCode',
            render: (text: string) => <span className="text-gray-500 font-mono text-xs">{text}</span>
        },
        {
            title: 'Số điện thoại',
            dataIndex: 'phoneNumber',
            key: 'phoneNumber',
        },
        {
            title: 'Gói hiện tại',
            key: 'plan',
            render: (_: any, record: any) => (
                <Tag color="cyan">{record.planName || 'Gói #' + record.planId}</Tag>
            )
        },
        {
            title: 'Hết hạn ngày',
            key: 'expiryDate',
            render: (_: any, record: any) => {
                const date = record.membershipExpiryDate ? new Date(record.membershipExpiryDate) : null;
                return (
                    <span className="text-red-500 font-semibold">
                        {date ? date.toLocaleDateString('vi-VN') : 'N/A'}
                    </span>
                );
            }
        },
        {
            title: 'Số xe',
            key: 'vehicles',
            render: (_: any, record: any) => (
                <Tooltip title={`${record.vehicles?.length || 0} xe đã đăng ký`}>
                    <Tag icon={<CarOutlined />}>
                        {record.vehicles?.length || 0}
                    </Tag>
                </Tooltip>
            )
        },
        {
            key: 'action',
            render: (_: any, record: any) => (
                <Button
                    type="primary"
                    ghost
                    size="small"
                    icon={<ReloadOutlined />}
                    onClick={(e) => {
                        e.stopPropagation(); // Prevent row click
                        handleRenew(record.id);
                    }}
                >
                    Gia hạn
                </Button>
            ),
        },
    ];

    const dataSource = (expiringMembersData as any)?.data || [];

    return (
        <div>
            <div className="mb-4 flex justify-between items-center">
                <div className="flex items-center gap-2 text-orange-600 bg-orange-50 px-3 py-1 rounded-md border border-orange-200">
                    <WarningOutlined />
                    <span className="font-medium">Danh sách các thành viên sắp hết hạn trong 7 ngày tới</span>
                </div>
                <Button icon={<ReloadOutlined />} onClick={() => refetch()}>Làm mới</Button>
            </div>

            <Table
                columns={columns}
                dataSource={dataSource}
                rowKey="id"
                loading={isLoading}
                onRow={(record) => ({
                    onClick: () => {
                        setViewMember(record);
                        setIsViewModalVisible(true);
                    },
                    style: { cursor: 'pointer' },
                })}
            />

            <ExpiringMemberDetailModal
                visible={isViewModalVisible}
                member={viewMember}
                onClose={() => setIsViewModalVisible(false)}
                onRenew={handleRenew}
            />
        </div>
    );
};

export default ExpiringMembersTab;

import React, { useRef } from 'react';
import { Modal, Descriptions, Tag, Button, Divider, Spin, Tooltip } from 'antd'; // Removed PrinterOutlined
import { PrinterOutlined, DownloadOutlined, CarOutlined } from '@ant-design/icons';
import { useGetMemberByIdQuery } from '../../../api/app_member/apiMember';
import { Invoice } from '../../../api/app_invoice/apiInvoice';
import dayjs from 'dayjs';

interface InvoiceModalProps {
    visible: boolean;
    invoice: Invoice | null;
    onClose: () => void;
}

const InvoiceModal: React.FC<InvoiceModalProps> = ({ visible, invoice, onClose }) => {
    const { data: memberData, isLoading } = useGetMemberByIdQuery(invoice?.memberId || 0, {
        skip: !invoice?.memberId,
    });

    const member = memberData?.data;

    const handlePrint = () => {
        window.print();
    };

    if (!invoice) return null;

    return (
        <Modal
            title={<span className="text-lg font-bold text-blue-800">Chi Tiết Hóa Đơn</span>}
            open={visible}
            onCancel={onClose}
            width={800}
            footer={[
                <Button key="close" onClick={onClose}>Đóng</Button>,
                <Button key="print" type="primary" icon={<PrinterOutlined />} onClick={handlePrint}>In hóa đơn</Button>
            ]}
            className="invoice-modal"
        >
            {isLoading ? (
                <div className="flex justify-center p-8"><Spin tip="Đang tải thông tin..." /></div>
            ) : (
                <div className="p-4" id="invoice-content">
                    <div className="flex justify-between items-start border-b pb-4 mb-4">
                        <div>
                            <h2 className="text-2xl font-bold text-slate-800">HÓA ĐƠN DỊCH VỤ</h2>
                            <p className="text-sm text-gray-500">Mã hóa đơn: <span className="font-mono font-bold text-gray-800">{invoice.invoiceCode}</span></p>
                            <p className="text-sm text-gray-500">Ngày tạo: {dayjs(invoice.createdAt).format('DD/MM/YYYY HH:mm')}</p>
                        </div>
                        <div className="text-right">
                            <Tag color={invoice.status === 'PAID' ? 'green' : invoice.status === 'OVERDUE' ? 'red' : 'orange'} className="text-base px-3 py-1">
                                {invoice.status === 'PAID' ? 'ĐÃ THANH TOÁN' : invoice.status === 'OVERDUE' ? 'QUÁ HẠN' : 'CHƯA THANH TOÁN'}
                            </Tag>
                            {invoice.status === 'UNPAID' && (
                                <p className="text-xs text-red-500 mt-1">Hạn TT: {dayjs(invoice.paymentDeadline).format('DD/MM/YYYY')}</p>
                            )}
                        </div>
                    </div>

                    {/* Member Info */}
                    <div className="mb-6 bg-slate-50 p-4 rounded-lg">
                        <Descriptions title="Thông Tin Khách Hàng" column={2} size="small">
                            <Descriptions.Item label="Khách hàng"><span className="font-semibold">{member?.fullname}</span></Descriptions.Item>
                            <Descriptions.Item label="Mã thành viên">{member?.memberCode}</Descriptions.Item>
                            <Descriptions.Item label="Số điện thoại">{member?.phoneNumber}</Descriptions.Item>
                            <Descriptions.Item label="Email">{member?.email}</Descriptions.Item>
                            <Descriptions.Item label="Địa chỉ/Phòng">{member?.roomNumber}</Descriptions.Item>
                            <Descriptions.Item label="Xe đăng ký">
                                <Tooltip title={
                                    <div>
                                        {member?.vehicles.map((v: any) => (
                                            <div key={v.id}>{v.licensePlate} ({v.vehicleType})</div>
                                        ))}
                                    </div>
                                }>
                                    <Tag icon={<CarOutlined />}>
                                        {member?.vehicles[0].licensePlate} (+{member?.vehicles.length - 1})
                                    </Tag>
                                </Tooltip>
                            </Descriptions.Item>
                        </Descriptions>
                    </div>

                    {/* Service Details */}
                    <div className="mb-6">
                        <h3 className="font-bold text-slate-700 mb-3 border-l-4 border-blue-500 pl-2">Chi Tiết Dịch Vụ</h3>
                        <table className="w-full text-sm text-left text-gray-500">
                            <thead className="text-xs text-gray-700 uppercase bg-gray-100">
                                <tr>
                                    <th className="px-4 py-2">Dịch vụ</th>
                                    <th className="px-4 py-2">Gói</th>
                                    <th className="px-4 py-2">Thời gian</th>
                                    <th className="px-4 py-2 text-right">Thành tiền</th>
                                </tr>
                            </thead>
                            <tbody>
                                <tr className="bg-white border-b">
                                    <td className="px-4 py-3 font-medium text-gray-900">
                                        {invoice.type === 'MEMBERSHIP' ? 'Đăng ký thành viên' : 'Phí gửi xe'}
                                        <div className="text-xs text-gray-400 font-normal">{member?.parkingLotName}</div>
                                    </td>
                                    <td className="px-4 py-3">
                                        {member?.planName}
                                    </td>
                                    <td className="px-4 py-3">
                                        {member?.membershipStartDate && member?.membershipExpiryDate ? (
                                            <span>{dayjs(member.membershipStartDate).format('DD/MM/YYYY')} - {dayjs(member.membershipExpiryDate).format('DD/MM/YYYY')}</span>
                                        ) : 'N/A'}
                                    </td>
                                    <td className="px-4 py-3 text-right font-bold text-gray-900">
                                        {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(invoice.amount)}
                                    </td>
                                </tr>
                            </tbody>
                            <tfoot>
                                <tr className="font-bold text-gray-900 bg-gray-50">
                                    <td colSpan={3} className="px-4 py-3 text-right">TỔNG CỘNG</td>
                                    <td className="px-4 py-3 text-right text-lg text-blue-600">
                                        {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(invoice.amount)}
                                    </td>
                                </tr>
                            </tfoot>
                        </table>
                    </div>

                    {/* Vehicle Info */}
                    {member?.vehicles && member.vehicles.length > 0 && (
                        <div className="mb-4">
                            <h4 className="text-sm font-bold text-gray-600 mb-2">Xe Đăng Ký:</h4>
                            <div className="flex gap-2">
                                {member.vehicles.map((v: any) => (
                                    <Tag key={v.id} icon={<CarOutlined />}>{v.licensePlate} - {v.vehicleType}</Tag>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Footer */}
                    <div className="mt-8 text-center text-xs text-gray-400 border-t pt-4">
                        <p>Cảm ơn quý khách đã sử dụng dịch vụ của Parkivia!</p>
                        <p>Vui lòng thanh toán trước ngày {dayjs(invoice.paymentDeadline).format('DD/MM/YYYY')} để tránh gián đoạn dịch vụ.</p>
                    </div>
                </div>
            )}
        </Modal>
    );
};

export default InvoiceModal;

import React, { useState, useEffect } from 'react';
import { Modal, Descriptions, Button, Tag, Form, Input, DatePicker, message, Space, List, Avatar, Select } from 'antd';
import { EditOutlined, CarOutlined, SaveOutlined, StopOutlined, MinusCircleOutlined, PlusOutlined } from '@ant-design/icons';
import { useGetMemberByIdQuery, useUpdateMemberMutation } from '../../../api/app_member/apiMember';
import dayjs from 'dayjs';

interface MemberDetailModalProps {
    open: boolean;
    memberId: number | null;
    onCancel: () => void;
    onSuccess: () => void;
}

const MemberDetailModal: React.FC<MemberDetailModalProps> = ({ open, memberId, onCancel, onSuccess }) => {
    const { data: memberDetail, isFetching, refetch } = useGetMemberByIdQuery(memberId!, {
        skip: !memberId
    });
    const [updateMember, { isLoading: isUpdating }] = useUpdateMemberMutation();

    const [isEditing, setIsEditing] = useState(false);
    const [form] = Form.useForm();

    useEffect(() => {
        if (open) {
            setIsEditing(false);
            if (memberId) refetch();
        }
    }, [open, memberId]);

    useEffect(() => {
        if (isEditing && memberDetail?.data) {
            const vehicles = (memberDetail.data.vehicles || []).map((v: any) => ({
                ...v,
                vehicleType: v.vehicleType === 'Ô tô' ? 'CAR' : (v.vehicleType === 'Xe máy' ? 'MOTORBIKE' : v.vehicleType)
            }));

            form.setFieldsValue({
                fullname: memberDetail.data.fullname,
                phoneNumber: memberDetail.data.phoneNumber,
                email: memberDetail.data.email,
                dateOfBirth: memberDetail.data.dateOfBirth ? dayjs(memberDetail.data.dateOfBirth) : null,
                address: memberDetail.data.address,
                vehicles: vehicles
            });
        }
    }, [isEditing]); // Removed memberDetail from dependencies to prevent reset

    const handleUpdate = async (values: any) => {
        if (!memberId) return;
        try {
            const payload = {
                ...values,
                dateOfBirth: values.dateOfBirth ? values.dateOfBirth.format('YYYY-MM-DD') : null
            };
            await updateMember({ id: memberId, data: payload }).unwrap();
            message.success('Cập nhật thông tin thành công');
            setIsEditing(false);
            refetch();
            onSuccess();
        } catch (error) {
            message.error('Cập nhật thất bại');
        }
    };

    const renderVehicles = (vehicles: any[]) => {
        if (!vehicles || vehicles.length === 0) return <span className="text-gray-400">Chưa có xe đăng ký</span>;
        return (
            <List
                itemLayout="horizontal"
                dataSource={vehicles}
                renderItem={(item: any) => (
                    <List.Item>
                        <List.Item.Meta
                            avatar={<Avatar icon={<CarOutlined />} className="bg-blue-100 text-blue-600" />}
                            title={<span className="font-semibold">{item.licensePlate}</span>}
                            description={<Tag color="blue">{item.vehicleType}</Tag>}
                        />
                    </List.Item>
                )}
            />
        );
    };

    const member = memberDetail?.data;

    return (
        <Modal
            title={isEditing ? "Chỉnh sửa thông tin thành viên" : "Chi tiết thành viên"}
            open={open}
            onCancel={onCancel}
            footer={null}
            width={800}
            destroyOnClose
        >
            {isFetching ? (
                <div className="p-8 text-center text-gray-500">Đang tải thông tin...</div>
            ) : member ? (
                isEditing ? (
                    <Form
                        form={form}
                        layout="vertical"
                        onFinish={handleUpdate}
                        className="mt-4"
                    >
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <Form.Item name="fullname" label="Họ và tên" rules={[{ required: true }]}>
                                <Input />
                            </Form.Item>
                            <Form.Item name="phoneNumber" label="Số điện thoại" rules={[{ required: true }]}>
                                <Input />
                            </Form.Item>
                            <Form.Item name="email" label="Email" rules={[{ required: true, type: 'email' }]}>
                                <Input />
                            </Form.Item>
                            <Form.Item name="dateOfBirth" label="Ngày sinh">
                                <DatePicker format="DD/MM/YYYY" className="w-full" />
                            </Form.Item>
                            <Form.Item name="address" label="Địa chỉ" className="md:col-span-2">
                                <Input />
                            </Form.Item>
                        </div>

                        <div className="mt-4 border-t pt-4">
                            <h4 className="font-bold mb-3">Danh sách xe</h4>
                            <Form.List name="vehicles">
                                {(fields, { add, remove }) => (
                                    <>
                                        {fields.map(({ key, name, ...restField }) => (
                                            <Space key={key} style={{ display: 'flex', marginBottom: 8 }} align="baseline">
                                                <Form.Item
                                                    {...restField}
                                                    name={[name, 'id']}
                                                    hidden
                                                >
                                                    <Input />
                                                </Form.Item>
                                                <Form.Item
                                                    {...restField}
                                                    name={[name, 'licensePlate']}
                                                    rules={[{ required: true, message: 'Nhập biển số' }]}
                                                >
                                                    <Input placeholder="Biển số" />
                                                </Form.Item>
                                                <Form.Item
                                                    {...restField}
                                                    name={[name, 'vehicleType']}
                                                    rules={[{ required: true, message: 'Chọn loại xe' }]}
                                                >
                                                    <Select placeholder="Loại xe" style={{ width: 120 }}>
                                                        <Select.Option value="MOTORBIKE">Xe máy</Select.Option>
                                                        <Select.Option value="CAR">Ô tô</Select.Option>
                                                    </Select>
                                                </Form.Item>
                                                <MinusCircleOutlined onClick={() => remove(name)} style={{ color: 'red' }} />
                                            </Space>
                                        ))}
                                        <Form.Item>
                                            <Button type="dashed" onClick={() => add({ vehicleType: 'MOTORBIKE' })} block icon={<PlusOutlined />}>
                                                Thêm xe
                                            </Button>
                                        </Form.Item>
                                    </>
                                )}
                            </Form.List>
                        </div>

                        <div className="flex justify-end gap-2 mt-4">
                            <Button onClick={() => setIsEditing(false)}>Hủy</Button>
                            <Button type="primary" htmlType="submit" loading={isUpdating} icon={<SaveOutlined />}>
                                Lưu thay đổi
                            </Button>
                        </div>
                    </Form>
                ) : (
                    <div>
                        <div className="flex justify-end mb-4">
                            {member.memberStatus === 'ACTIVE' && (
                                <Button type="primary" icon={<EditOutlined />} onClick={() => setIsEditing(true)}>
                                    Sửa thông tin
                                </Button>
                            )}
                        </div>

                        <Descriptions bordered column={{ xxl: 2, xl: 2, lg: 2, md: 1, sm: 1, xs: 1 }}>
                            <Descriptions.Item label="Mã thành viên">{member.memberCode}</Descriptions.Item>
                            <Descriptions.Item label="Trạng thái">
                                <Tag color={member.memberStatus === 'ACTIVE' ? 'green' : (member.memberStatus === 'LOCKED' ? 'red' : 'default')}>
                                    {member.memberStatus}
                                </Tag>
                            </Descriptions.Item>
                            <Descriptions.Item label="Họ và tên">{member.fullname}</Descriptions.Item>
                            <Descriptions.Item label="Ngày sinh">{member.dateOfBirth ? dayjs(member.dateOfBirth).format('DD/MM/YYYY') : '-'}</Descriptions.Item>
                            <Descriptions.Item label="Số điện thoại">{member.phoneNumber}</Descriptions.Item>
                            <Descriptions.Item label="Email">{member.email}</Descriptions.Item>
                            <Descriptions.Item label="Bãi xe">{member.parkingLotName}</Descriptions.Item>
                            <Descriptions.Item label="Gói đăng ký">{member.planName}</Descriptions.Item>
                            <Descriptions.Item label="Ngày tham gia">{member.membershipStartDate ? dayjs(member.membershipStartDate).format('DD/MM/YYYY') : '-'}</Descriptions.Item>
                            <Descriptions.Item label="Ngày hết hạn">{member.membershipExpiryDate ? dayjs(member.membershipExpiryDate).format('DD/MM/YYYY') : '-'}</Descriptions.Item>

                            {member.memberStatus === 'LOCKED' && (
                                <Descriptions.Item label="Lý do khóa" span={2}>
                                    <span className="text-red-500">{member.lockReason}</span>
                                </Descriptions.Item>
                            )}
                        </Descriptions>

                        <div className="mt-6">
                            <h4 className="font-bold mb-3 flex items-center gap-2">
                                <CarOutlined /> Danh sách xe đăng ký
                            </h4>
                            <div className="bg-gray-50 p-4 rounded-lg border border-gray-200">
                                {renderVehicles(member.vehicles)}
                            </div>
                        </div>
                    </div>
                )
            ) : (
                <div className="text-center text-red-500">Không tìm thấy thông tin thành viên</div>
            )}
        </Modal>
    );
};

export default MemberDetailModal;

import React, { useState } from 'react';
import { Table, Button, Tag, Space, message, Popconfirm, Modal, Input, Tooltip } from 'antd';
import PendingMemberDetailModal from './PendingMemberDetailModal';
import { useGetPendingMembersQuery, useApproveMemberMutation, useRejectMemberMutation } from '../../../api/app_member/apiMember';
import { useCreateMembershipInvoiceMutation } from '../../../api/app_invoice/apiInvoice';
import { CheckOutlined, CloseOutlined, CarOutlined } from '@ant-design/icons';

const PendingMembersTab: React.FC = () => {
    const { data: pendingMembersData, isLoading, refetch } = useGetPendingMembersQuery();
    const [approveMember] = useApproveMemberMutation();
    const [createInvoice] = useCreateMembershipInvoiceMutation();
    const [rejectMember] = useRejectMemberMutation();

    const [isRejectModalVisible, setIsRejectModalVisible] = useState(false);
    const [selectedMemberId, setSelectedMemberId] = useState<number | null>(null);
    const [rejectionReason, setRejectionReason] = useState('');

    const [viewMember, setViewMember] = useState<any | null>(null);
    const [isViewModalVisible, setIsViewModalVisible] = useState(false);

    const handleApprove = async (id: number) => {
        try {
            await approveMember(id).unwrap();
            message.success('Đã duyệt thành viên và tạo hóa đơn thành công');
            refetch();
        } catch (error) {
            console.error(error);
            message.error('Có lỗi xảy ra khi duyệt hoặc tạo hóa đơn');
        }
    };

    const showRejectModal = (id: number) => {
        setSelectedMemberId(id);
        setRejectionReason('');
        setIsRejectModalVisible(true);
    };

    const handleRejectConfirm = async () => {
        if (!selectedMemberId) return;
        if (!rejectionReason.trim()) {
            message.error('Vui lòng nhập lý do từ chối');
            return;
        }

        try {
            await rejectMember({ id: selectedMemberId, reason: rejectionReason }).unwrap();
            message.success('Đã từ chối thành viên');
            setIsRejectModalVisible(false);
            refetch();
        } catch (error) {
            message.error('Có lỗi xảy ra');
        }
    };

    const columns = [
        {
            title: 'Họ và tên',
            dataIndex: 'fullname',
            key: 'fullname',
        },
        {
            title: 'Số điện thoại',
            dataIndex: 'phoneNumber',
            key: 'phoneNumber',
        },
        {
            title: 'Email',
            dataIndex: 'email',
            key: 'email',
        },
        {
            title: 'Xe đăng ký',
            key: 'vehicles',
            render: (_: any, record: any) => {
                // Handle both flat structure (legacy) and nested vehicles array
                const vehicles = record.vehicles || [];
                if (vehicles.length > 0) {
                    if (vehicles.length === 1) {
                        return (
                            <Tag icon={<CarOutlined />}>
                                {vehicles[0].licensePlate} ({vehicles[0].vehicleType})
                            </Tag>
                        );
                    }
                    return (
                        <Tooltip title={
                            <div>
                                {vehicles.map((v: any) => (
                                    <div key={v.id}>{v.licensePlate} ({v.vehicleType})</div>
                                ))}
                            </div>
                        }>
                            <Tag icon={<CarOutlined />}>
                                {vehicles[0].licensePlate} (+{vehicles.length - 1})
                            </Tag>
                        </Tooltip>
                    );
                }

                // Fallback for flat structure if API returns mixed data
                if (record.licensePlate) {
                    return (
                        <Tag icon={<CarOutlined />}>
                            {record.licensePlate} ({record.vehicleType})
                        </Tag>
                    );
                }

                return <span className="text-gray-400">Không có xe</span>;
            }
        },
        {
            title: 'Gói đăng ký',
            key: 'plan',
            render: (_: any, record: any) => (
                <Tag color="blue">{record.planName || 'Gói #' + record.planId}</Tag>
            )
        },
        {
            title: 'Bãi đỗ xe',
            dataIndex: 'parkingLotName',
            key: 'parkingLotName',
        },
        {
            key: 'action',
            render: (_: any, record: any) => (
                <Space size="middle">
                    <Popconfirm title="Duyệt thành viên này?" onConfirm={() => handleApprove(record.id)}>
                        <Button type="primary" icon={<CheckOutlined />} className="bg-green-600">Duyệt</Button>
                    </Popconfirm>
                    <Button danger icon={<CloseOutlined />} onClick={() => showRejectModal(record.id)}>Từ chối</Button>
                </Space>
            ),
        },
    ];

    const dataSource = (pendingMembersData as any)?.data || [];

    return (
        <div>
            <div className="mb-4 flex justify-end">
                <Button onClick={() => refetch()}>Làm mới</Button>
            </div>
            <Table
                columns={columns}
                dataSource={dataSource}
                rowKey="id"
                loading={isLoading}
                onRow={(record) => ({
                    onClick: () => {
                        setViewMember(record);
                        setIsViewModalVisible(true);
                    },
                    style: { cursor: 'pointer' },
                })}
            />

            <PendingMemberDetailModal
                visible={isViewModalVisible}
                member={viewMember}
                onClose={() => setIsViewModalVisible(false)}
                onApprove={handleApprove}
                onReject={showRejectModal}
            />

            <Modal
                title="Từ chối thành viên"
                open={isRejectModalVisible}
                onOk={handleRejectConfirm}
                onCancel={() => setIsRejectModalVisible(false)}
                okText="Xác nhận từ chối"
                okButtonProps={{ danger: true }}
                cancelText="Hủy"
            >
                <p>Vui lòng nhập lý do từ chối yêu cầu thành viên này:</p>
                <Input.TextArea
                    rows={4}
                    value={rejectionReason}
                    onChange={(e) => setRejectionReason(e.target.value)}
                    placeholder="Nhập lý do..."
                />
            </Modal>
        </div>
    );
};

