export default ParkVehicleForm;

import React, { useState, useRef, useEffect } from 'react';
import { Card, Row, Col, Typography, Tag, Space, Spin, Divider, Button, Modal, message, Input, Select } from 'antd';
import { useGetAllParkingLotsQuery, ParkingLot } from '../../../api/app_parkinglot/apiParkinglot';
import { useCreateParkingEntryMutation, useGetAllParkingEntriesQuery, useRecognizeLicensePlateMutation, useCreateMemberParkingEntryMutation } from '../../../api/app_parking/apiParking';
import { useLazyGetMemberByCodeQuery } from '../../../api/app_member/apiMember';
import { CarOutlined, EnvironmentOutlined, ClockCircleOutlined, DollarOutlined, TagOutlined, CameraOutlined } from '@ant-design/icons';
import './ParkVehicle.css';

import jsQR from 'jsqr';

const { Text } = Typography;

const ParkVehicleTab: React.FC = () => {
    const { data: parkingLots, isLoading, refetch } = useGetAllParkingLotsQuery({});
    const [createParkingEntry] = useCreateParkingEntryMutation();
    const [createMemberParkingEntry] = useCreateMemberParkingEntryMutation();
    const [recognizeLicensePlate] = useRecognizeLicensePlateMutation();
    const [getMemberByCode] = useLazyGetMemberByCodeQuery();
    const [isCameraModalOpen, setIsCameraModalOpen] = useState(false);
    const [selectedLot, setSelectedLot] = useState<ParkingLot | null>(null);
    const [isConfirmModalOpen, setIsConfirmModalOpen] = useState(false);
    const [correctedPlate, setCorrectedPlate] = useState<string>('');
    const [selectedVehicleType, setSelectedVehicleType] = useState<string>('');
    const [capturedBlob, setCapturedBlob] = useState<Blob | null>(null);
    const [isSuccessModalOpen, setIsSuccessModalOpen] = useState(false);
    const [parkingCode, setParkingCode] = useState<number | null>(null);
    const [scannedMemberCode, setScannedMemberCode] = useState<string | null>(null);
    const videoRef = useRef<HTMLVideoElement>(null);
    const streamRef = useRef<MediaStream | null>(null);
    const { data: entries } = useGetAllParkingEntriesQuery();

    const parseVehicleTypes = (vehicleTypesStr: string) => {
        try {
            return vehicleTypesStr.replace(/[[\]]/g, '').split(',').map(type => type.trim());
        } catch {
            return [];
        }
    };

    const generateUniqueCode = () => {
        const existingCodes = entries?.map(e => e.code) || [];
        let code: number;
        do {
            code = Math.floor(100 + Math.random() * 900);
        } while (existingCodes.includes(code));
        return code;
    };

    const scanningRef = useRef<boolean>(false);

    const scanQRCode = React.useCallback(() => {
        if (!scanningRef.current || !videoRef.current || videoRef.current.readyState !== videoRef.current.HAVE_ENOUGH_DATA) {
            if (scanningRef.current) requestAnimationFrame(scanQRCode);
            return;
        }

        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        const ctx = canvas.getContext('2d');
        if (ctx) {
            ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
            const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
            const code = jsQR(imageData.data, imageData.width, imageData.height, {
                inversionAttempts: "dontInvert",
            });

            if (code && !scannedMemberCode) {
                console.log("QR Code detected (Real-time):", code.data);
                scanningRef.current = false;

                getMemberByCode(code.data).unwrap()
                    .then(memberRes => {
                        const memberData = memberRes.data;
                        message.success(`Đã nhận diện TV ${memberData.fullname || ''}. Vui lòng hướng camera chụp biển số xe.`);
                        setScannedMemberCode(code.data);
                        if (memberData && memberData.vehicles && memberData.vehicles.length > 0) {
                            setCorrectedPlate(memberData.vehicles[0].licensePlate);
                            setSelectedVehicleType(memberData.vehicles[0].vehicleType);
                        }
                    })
                    .catch(err => {
                        message.error('Không tìm thấy thông tin thành viên từ mã QR này');
                        scanningRef.current = true;
                        requestAnimationFrame(scanQRCode);
                    });

                return;
            }
        }
        requestAnimationFrame(scanQRCode);
    }, [getMemberByCode, scannedMemberCode]);

    const startCamera = React.useCallback(async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
                streamRef.current = stream;
                scanningRef.current = true;
                requestAnimationFrame(scanQRCode);
            }
        } catch {
            message.error('Không thể truy cập camera');
            setIsCameraModalOpen(false);
        }
    }, [scanQRCode]);

    const stopCamera = React.useCallback(() => {
        scanningRef.current = false;
        streamRef.current?.getTracks().forEach(track => track.stop());
        streamRef.current = null;
    }, []);

    const captureImage = async () => {
        if (!videoRef.current || !selectedLot) return;

        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
        // Nếu đã quét QR thành công ở bước trước, thao tác này là chụp ảnh BIỂN SỐ
        if (scannedMemberCode) {
            canvas.toBlob(async blob => {
                if (blob) {
                    setCapturedBlob(blob);
                    stopCamera();
                    setIsCameraModalOpen(false);

                    const formData = new FormData();
                    formData.append('image', blob, 'plate.jpg');
                    message.loading({ content: 'Đang trích xuất ảnh và nhận diện biển số...', key: 'recognize' });

                    try {
                        let recognizedPlate = '';
                        try {
                            const recognitionResult = await recognizeLicensePlate(formData).unwrap();
                            if (recognitionResult && recognitionResult.plate && recognitionResult.plate.trim() !== '') {
                                recognizedPlate = recognitionResult.plate.trim();
                            }
                        } catch (e) {
                            console.error('Lỗi nhận diện:', e);
                        }

                        const memberRes = await getMemberByCode(scannedMemberCode).unwrap();
                        const memberData = memberRes.data;

                        if (memberData && memberData.vehicles && memberData.vehicles.length > 0) {
                            if (recognizedPlate) {
                                const cleanPlate = (p: string) => p.replace(/[-.\s_]/g, '').toUpperCase();
                                const recognizedClean = cleanPlate(recognizedPlate);

                                const matchedVehicle = memberData.vehicles.find(
                                    (v: any) => cleanPlate(v.licensePlate) === recognizedClean
                                );

                                if (matchedVehicle) {
                                    setCorrectedPlate(matchedVehicle.licensePlate);
                                    setSelectedVehicleType(matchedVehicle.vehicleType);
                                    message.success({ content: `Nhận diện thành công biển số: ${matchedVehicle.licensePlate}`, key: 'recognize' });
                                } else {
                                    setCorrectedPlate(recognizedPlate);
                                    message.warning({ content: `Không tìm thấy xe ${recognizedPlate} trong danh sách của thành viên. Vui lòng kiểm tra lại.`, key: 'recognize' });
                                }
                            } else {
                                setCorrectedPlate(memberData.vehicles[0].licensePlate);
                                setSelectedVehicleType(memberData.vehicles[0].vehicleType);
                                message.warning({ content: 'Không nhận diện được rõ biển số. Đã lấy xe mặc định.', key: 'recognize' });
                            }
                        } else {
                            if (recognizedPlate) setCorrectedPlate(recognizedPlate);
                            message.success({ content: 'Hoàn tất quá trình lấy thông tin', key: 'recognize' });
                        }
                    } catch (err) {
                        message.error({ content: 'Có lỗi xảy ra khi tải dữ liệu', key: 'recognize' });
                    }

                    setIsConfirmModalOpen(true);
                }
            }, 'image/jpeg', 0.8);
            return;
        }

        const qrCode = jsQR(imageData.data, imageData.width, imageData.height, {
            inversionAttempts: "attemptBoth",
        });

        // Nếu lúc nhấn chụp vô tình trúng QR (fallback)
        if (qrCode) {
            console.log("QR Code detected at capture:", qrCode.data);

            try {
                const memberRes = await getMemberByCode(qrCode.data).unwrap();
                const memberData = memberRes.data;
                message.success(`Đã nhận diện TV ${memberData.fullname || ''}. Vui lòng hướng camera chụp biển số xe.`);
                setScannedMemberCode(qrCode.data);
                if (memberData && memberData.vehicles && memberData.vehicles.length > 0) {
                    setCorrectedPlate(memberData.vehicles[0].licensePlate);
                    setSelectedVehicleType(memberData.vehicles[0].vehicleType);
                }
            } catch (err) {
                message.error('Không tìm thấy thông tin thành viên từ mã QR này');
            }
            return;
        }

        // Luồng thông thường: ảnh biển số tự do (chưa có member) quét AI
        canvas.toBlob(async blob => {
            if (blob) {
                setCapturedBlob(blob);
                setIsCameraModalOpen(false);
                const formData = new FormData();
                formData.append('image', blob, 'plate.jpg');

                try {
                    const recognitionResult = await recognizeLicensePlate(formData).unwrap();
                    if (recognitionResult && recognitionResult.plate && recognitionResult.plate.trim() !== '') {
                        setCorrectedPlate(recognitionResult.plate.trim());
                        setIsConfirmModalOpen(true);
                    } else {
                        message.error('Không thể nhận diện biển số xe. Vui lòng thử lại.');
                        setIsCameraModalOpen(true);
                        startCamera();
                    }
                } catch (error) {
                    message.error('Không thể nhận diện biển số xe. Vui lòng thử lại.');
                    setIsCameraModalOpen(true);
                    startCamera();
                }
                stopCamera();
            }
        }, 'image/jpeg', 0.8);
    };

    const handleConfirm = async () => {
        if (!selectedLot || !correctedPlate || !selectedVehicleType || !capturedBlob) {
            message.error("Vui lòng điền đầy đủ thông tin");
            return;
        }

        const form = new FormData();
        form.append("image", capturedBlob, "plate.jpg");

        try {
            let res;
            // Member checkin
            if (scannedMemberCode) {
                const payload = {
                    lotId: selectedLot.id,
                    licensePlate: correctedPlate,
                    vehicleType: selectedVehicleType,
                    memberCode: scannedMemberCode
                };
                const jsonBlob = new Blob([JSON.stringify(payload)], { type: "application/json" });
                form.append("data", jsonBlob);

                res = await createMemberParkingEntry(form);
            } else {
                // Normal checkin
                const code = generateUniqueCode();
                const payload = {
                    lotId: selectedLot.id,
                    licensePlate: correctedPlate,
                    code: code,
                    vehicleType: selectedVehicleType,
                };
                const jsonBlob = new Blob([JSON.stringify(payload)], { type: "application/json" });
                form.append("data", jsonBlob);

                res = await createParkingEntry(form);
            }

            if ('error' in res) {
                const apiError = res.error as { data?: { message?: string } };
                if (apiError.data && apiError.data.message === "An unexpected error occurred: Xe đã có phiên gửi xe đang hoạt động") {
                    message.error("Xe đã có phiên gửi xe đang hoạt động");
                } else {
                    message.error(apiError.data?.message || "Có lỗi xảy ra khi gửi xe");
                }
            } else {
                message.success("Gửi xe thành công!");
                setIsConfirmModalOpen(false);
                if (!scannedMemberCode) {
                    setParkingCode(res.data.code);
                    setIsSuccessModalOpen(true);
                } else {
                    // Của member thì không cần quan tâm mã code thẻ
                }
                setCorrectedPlate("");
                setSelectedVehicleType("");
                setCapturedBlob(null);
                setScannedMemberCode(null);
            }
        } catch (error) {
            message.error("Có lỗi xảy ra khi gửi xe");
        }
    };

    const handleParkClick = (lot: ParkingLot) => {
        setSelectedLot(lot);
        setCorrectedPlate('');
        setSelectedVehicleType('');
        setScannedMemberCode(null);
        setIsCameraModalOpen(true);
    };

    const handleCameraModalClose = () => {
        setIsCameraModalOpen(false);
        stopCamera();
        setScannedMemberCode(null);
    };

    useEffect(() => {
        if (isCameraModalOpen) {
            startCamera();
        } else {
            stopCamera();
        }
        return () => stopCamera();
    }, [isCameraModalOpen, startCamera, stopCamera]);

    if (isLoading) {
        return (
            <div style={{ textAlign: 'center', padding: '50px' }}>
                <Spin size="large" />
            </div>
        );
    }

    if (!parkingLots || parkingLots.length === 0) {
        return (
            <div style={{ textAlign: 'center', padding: '50px', color: '#999' }}>
                <Text>Không có bãi đỗ xe nào khả dụng.</Text>
            </div>
        );
    }

    return (
        <div className="park-vehicle-container">
            <Row gutter={[24, 24]}>
                {parkingLots?.map((lot: ParkingLot) => (
                    <Col xs={24} sm={12} md={8} lg={6} key={lot.id}>
                        <Card
                            hoverable
                            className="parking-lot-card"
                            title={
                                <div className="card-title">
                                    <CarOutlined className="card-icon" />
                                    <span>{lot.name}</span>
                                </div>
                            }
                        >
                            <Space direction="vertical" size="middle" style={{ width: '100%' }}>
                                <div className="info-section">
                                    <div className="info-item">
                                        <EnvironmentOutlined className="info-icon" />
                                        <Text>{lot.address}</Text>
                                    </div>
                                    <div className="info-item">
                                        <ClockCircleOutlined className="info-icon" />
                                        <Text>{lot.operatingHours}</Text>
                                    </div>
                                </div>

                                <Divider className="card-divider" />

                                <div className="capacity-section">
                                    <div className="capacity-info">
                                        <Text className="capacity-label">Sức chứa</Text>
                                        <Text className="capacity-value">{lot.capacity} xe</Text>
                                    </div>
                                    <div className="capacity-info">
                                        <Text className="capacity-label">Còn trống</Text>
                                        <Text className="capacity-value">{lot.availableSlots} chỗ</Text>
                                    </div>
                                </div>

                                <Divider className="card-divider" />

                                <div className="price-section">
                                    <div className="price-item">
                                        <DollarOutlined className="price-icon" />
                                        <div>
                                            <Text className="price-label">Giá theo giờ</Text>
                                            <Text className="price-value">{lot.hourlyRate.toLocaleString()}đ</Text>
                                        </div>
                                    </div>
                                    <div className="price-item">
                                        <DollarOutlined className="price-icon" />
                                        <div>
                                            <Text className="price-label">Giá theo ngày</Text>
                                            <Text className="price-value">{lot.dailyRate.toLocaleString()}đ</Text>
                                        </div>
                                    </div>
                                </div>

                                <Divider className="card-divider" />

                                <div className="tags-section">
                                    <div className="vehicle-types">
                                        <TagOutlined className="tags-icon" />
                                        <div className="tags-container">
                                            {parseVehicleTypes(lot.vehicleTypes).map((type, index) => (
                                                <Tag key={index} color="blue" className="vehicle-tag">
                                                    {type}
                                                </Tag>
                                            ))}
                                        </div>
                                    </div>
                                    <div className="status-tags">
                                        <Tag color={lot.isCovered ? 'green' : 'orange'} className="status-tag">
                                            {lot.isCovered ? 'Có mái che' : 'Không có mái che'}
                                        </Tag>
                                        <Tag color={lot.status === 'ACTIVE' ? 'green' : 'red'} className="status-tag">
                                            {lot.status === 'ACTIVE' ? 'Đang hoạt động' : 'Tạm ngưng'}
                                        </Tag>
                                    </div>
                                </div>

                                <Button
                                    type="primary"
                                    icon={<CameraOutlined />}
                                    onClick={() => handleParkClick(lot)}
                                    disabled={lot.status !== 'ACTIVE' || lot.availableSlots === 0}
                                    block
                                >
                                    Gửi xe
                                </Button>
                            </Space>
                        </Card>
                    </Col>
                ))}
            </Row>

            <Modal
                title="Chụp ảnh biển số xe"
                open={isCameraModalOpen}
                onCancel={handleCameraModalClose}
                footer={[
                    <Button key="capture" type="primary" onClick={captureImage}>
                        Chụp ảnh
                    </Button>
                ]}
                width={800}
            >
                <div className="camera-container">
                    <video
                        ref={videoRef}
                        autoPlay
                        playsInline
                        style={{ width: '100%', maxHeight: '500px' }}
                    />
                </div>
            </Modal>

            <Modal
                title="Xác nhận thông tin xe"
                open={isConfirmModalOpen}
                onCancel={() => setIsConfirmModalOpen(false)}
                onOk={handleConfirm}
                okText="Xác nhận"
                cancelText="Hủy"
            >
                <Space direction="vertical" style={{ width: '100%' }}>
                    <div>
                        <Text strong>Biển số xe:</Text>
                        <Input value={correctedPlate} onChange={e => setCorrectedPlate(e.target.value)} placeholder="Nhập biển số xe" />
                    </div>
                    <div>
                        <Text strong>Loại xe:</Text>
                        <Select
                            style={{ width: '100%' }}
                            value={selectedVehicleType}
                            onChange={setSelectedVehicleType}
                            placeholder="Chọn loại xe"
                        >
                            {selectedLot && parseVehicleTypes(selectedLot.vehicleTypes).map((type, idx) => (
                                <Select.Option key={idx} value={type}>{type}</Select.Option>
                            ))}
                        </Select>
                    </div>
                </Space>
            </Modal>

            <Modal
                title="Gửi xe thành công"
                open={isSuccessModalOpen}
                onOk={() => setIsSuccessModalOpen(false)}
                onCancel={() => setIsSuccessModalOpen(false)}
                footer={[
                    <Button key="close" type="primary" onClick={() => setIsSuccessModalOpen(false)}>
                        Đóng
                    </Button>
                ]}
            >
                <div style={{ textAlign: 'center', padding: '20px 0' }}>
                    <div style={{ marginBottom: '24px' }}>
                        <Text strong style={{ fontSize: '16px' }}>Mã xe của bạn là:</Text>
                    </div>
                    <div style={{
                        fontSize: '48px',
                        fontWeight: 'bold',
                        color: '#1890ff',
                        background: '#f0f5ff',
                        padding: '16px 32px',
                        borderRadius: '8px',
                        display: 'inline-block'
                    }}>
                        {parkingCode}
                    </div>
                    <div style={{ marginTop: '16px' }}>
                        <Text type="secondary">Vui lòng lưu lại mã này để lấy xe sau</Text>
                    </div>
                </div>
            </Modal>
        </div>
    );
};

export default ParkVehicleTab;

import React, { useState } from 'react';
import { Table, Button, Modal, Form, Input, InputNumber, Switch, message, Popconfirm, Select, Space } from 'antd';
import { PlusOutlined, EditOutlined, DeleteOutlined, GiftOutlined } from '@ant-design/icons';
import {
    useGetAllParkingPlansQuery,
    useCreateParkingPlanMutation,
    useUpdateParkingPlanMutation,
    useDeleteParkingPlanMutation,
    ParkingPlan
} from '../../api/app_parkingPlan/apiParkingPlan';
import { useGetAllParkingLotsQuery } from '../../api/app_parkinglot/apiParkinglot';

const ParkingPlanManage: React.FC = () => {
    const { data: parkingPlans = [], isLoading, refetch } = useGetAllParkingPlansQuery();
    const { data: parkingLots = [] } = useGetAllParkingLotsQuery({});
    const [createParkingPlan, { isLoading: isCreating }] = useCreateParkingPlanMutation();
    const [updateParkingPlan, { isLoading: isUpdating }] = useUpdateParkingPlanMutation();
    const [deleteParkingPlan, { isLoading: isDeleting }] = useDeleteParkingPlanMutation();

    const [isModalVisible, setIsModalVisible] = useState(false);
    const [editingPlan, setEditingPlan] = useState<ParkingPlan | null>(null);
    const [form] = Form.useForm();

    const handleAdd = () => {
        setEditingPlan(null);
        form.resetFields();
        setIsModalVisible(true);
    };

    const handleEdit = (record: ParkingPlan) => {
        setEditingPlan(record);
        form.setFieldsValue({
            ...record,
            priceUnit: record.priceUnit,
        });
        setIsModalVisible(true);
    };

    const handleDelete = async (id: number) => {
        try {
            await deleteParkingPlan(id).unwrap();
            message.success('Xóa gói thành công!');
            refetch();
        } catch (error) {
            message.error('Có lỗi xảy ra khi xóa!');
        }
    };

    const handleOk = async () => {
        try {
            const values = await form.validateFields();

            if (editingPlan) {
                await updateParkingPlan({ id: editingPlan.id, data: values }).unwrap();
                message.success('Cập nhật gói thành công!');
            } else {
                await createParkingPlan(values).unwrap();
                message.success('Thêm gói mới thành công!');
            }
            setIsModalVisible(false);
            refetch();
        } catch (error) {
            message.error('Có lỗi xảy ra!');
        }
    };

    const columns = [
        {
            title: 'Tên gói',
            dataIndex: 'name',
            key: 'name',
        },
        {
            title: 'Giá',
            dataIndex: 'price',
            key: 'price',
            render: (val: number, record: any) => `${new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(val)} / ${record.priceUnit}`,
        },
        {
            title: 'Loại gói',
            dataIndex: 'planType',
            key: 'planType',
        },
        {
            title: 'Mô tả',
            dataIndex: 'description',
            key: 'description',
            ellipsis: true,
        },
        {
            title: 'Bãi đỗ xe',
            dataIndex: 'parkingLotName',
            key: 'parkingLotName',
        },
        {
            title: 'Phổ biến',
            dataIndex: 'isPopular',
            key: 'isPopular',
            render: (val: boolean) => val ? 'Có' : 'Không',
        },
        {
            title: 'Hành động',
            key: 'action',
            render: (_: any, record: ParkingPlan) => (
                <Space>
                    <Button icon={<EditOutlined />} onClick={() => handleEdit(record)} />
                    <Popconfirm title="Bạn có chắc chắn muốn xóa?" onConfirm={() => handleDelete(record.id)}>
                        <Button icon={<DeleteOutlined />} danger />
                    </Popconfirm>
                </Space>
            ),
        },
    ];

    return (
        <div className="p-6">
            <h1 className="text-2xl font-bold mb-4">Quản lý các gói thành viên</h1>
            <Button type="primary" icon={<PlusOutlined />} onClick={handleAdd} className="mb-4">
                Thêm gói mới
            </Button>
            <Table
                dataSource={Array.isArray(parkingPlans) ? parkingPlans : (parkingPlans as any)?.data || []}
                columns={columns}
                rowKey="id"
                loading={isLoading}
            />

            <Modal
                title={editingPlan ? "Cập nhật gói" : "Thêm gói mới"}
                open={isModalVisible}
                onOk={handleOk}
                onCancel={() => setIsModalVisible(false)}
                confirmLoading={isCreating || isUpdating}
                width={800}
            >
                <Form form={form} layout="vertical">
                    <Form.Item name="name" label="Tên gói" rules={[{ required: true }]}>
                        <Input />
                    </Form.Item>

                    <Form.Item
                        name="parkingLotId"
                        label="Bãi đỗ xe áp dụng aaa"
                        rules={[{ required: true, message: 'Vui lòng chọn bãi đỗ xe!' }]}
                    >
                        <Select placeholder="Chọn bãi đỗ xe">
                            {(Array.isArray(parkingLots) ? parkingLots : (parkingLots as any)?.data || []).map((lot: any) => (
                                <Select.Option key={lot.id} value={lot.id}>{lot.name}</Select.Option>
                            ))}
                        </Select>
                    </Form.Item>

                    <div className="grid grid-cols-2 gap-4">
                        <Form.Item name="price" label="Giá (VND)" rules={[{ required: true }]}>
                            <InputNumber style={{ width: '100%' }} />
                        </Form.Item>
                        <Form.Item name="priceUnit" label="Chu kỳ" rules={[{ required: true }]}>
                            <Select>
                                <Select.Option value="DAY">Ngày</Select.Option>
                                <Select.Option value="MONTH">Tháng</Select.Option>
                                <Select.Option value="YEAR">Năm</Select.Option>
                            </Select>
                        </Form.Item>
                        <Form.Item name="planType" label="Loại gói (VD: STANDARD, PREMIUM)" rules={[{ required: true }]}>
                            <Input />
                        </Form.Item>
                    </div>
                    <Form.Item name="description" label="Mô tả">
                        <Input.TextArea rows={2} />
                    </Form.Item>
                    <div className="grid grid-cols-2 md:grid-cols-3 gap-4 bg-gray-50 p-4 rounded-lg">
                        <Form.Item name="isUnlimitedParking" valuePropName="checked" label="Đỗ xe không giới hạn">
                            <Switch />
                        </Form.Item>
                        <Form.Item name="hasFixedSpot" valuePropName="checked" label="Chỗ cố định">
                            <Switch />
                        </Form.Item>
                        <Form.Item name="hasValetService" valuePropName="checked" label="Valet Parking">
                            <Switch />
                        </Form.Item>
                        <Form.Item name="hasCarWash" valuePropName="checked" label="Rửa xe miễn phí">
                            <Switch />
                        </Form.Item>
                        <Form.Item name="hasCoveredParking" valuePropName="checked" label="Có mái che">
                            <Switch />
                        </Form.Item>
                        <Form.Item name="hasSecurity247" valuePropName="checked" label="An ninh 24/7">
                            <Switch />
                        </Form.Item>
                    </div>

                    <div className="grid grid-cols-2 gap-4 mt-4">
                        <Form.Item name="isPopular" valuePropName="checked" label="Gói Phổ biến">
                            <Switch />
                        </Form.Item>
                        <Form.Item name="isActive" valuePropName="checked" label="Đang hoạt động">
                            <Switch />
                        </Form.Item>
                    </div>
                </Form>
            </Modal>
        </div>
    );
};

export default ParkingPlanManage;

import React, { useEffect } from 'react';
import { Modal, Form, Input, InputNumber, Switch, Select, Button } from 'antd';
import { CreateParkingLotRequest, UpdateParkingLotRequest, ParkingLot } from '../../../api/app_parkinglot/apiParkinglot';

const { Option } = Select;

interface CreateAndUpdateParkingLotProps {
    visible: boolean;
    onClose: () => void;
    onSubmit: (values: CreateParkingLotRequest | UpdateParkingLotRequest) => Promise<void>;
    initialValues?: ParkingLot;
    isEditing: boolean;
}

const CreateAndUpdateParkingLot: React.FC<CreateAndUpdateParkingLotProps> = ({
    visible,
    onClose,
    onSubmit,
    initialValues,
    isEditing
}) => {
    const [form] = Form.useForm();

    useEffect(() => {
        if (visible) {
            if (isEditing && initialValues) {
                form.setFieldsValue({
                    ...initialValues,
                    vehicleTypes: initialValues.vehicleTypes
                        .replace(/[\[\]]/g, '')
                        .split(',')
                        .map((type: string) => type.trim())
                });
            } else {
                form.resetFields();
                form.setFieldsValue({
                    status: 'ACTIVE',
                    isCovered: false
                });
            }
        }
    }, [visible, isEditing, initialValues, form]);

    const handleOk = async () => {
        try {
            const values = await form.validateFields();
            const formattedValues = {
                ...values,
                vehicleTypes: Array.isArray(values.vehicleTypes)
                    ? values.vehicleTypes.join(', ')
                    : values.vehicleTypes
            };
            await onSubmit(formattedValues);
            form.resetFields();
        } catch (error) {
            console.error('Submission failed:', error);
        }
    };

    return (
        <Modal
            title={isEditing ? 'Chỉnh sửa bãi đỗ' : 'Thêm bãi đỗ'}
            open={visible}
            onCancel={() => {
                form.resetFields();
                onClose();
            }}
            footer={[
                <Button
                    key="submit"
                    type="primary"
                    onClick={handleOk}
                >
                    {isEditing ? 'Cập nhật' : 'Thêm'}
                </Button>,
                <Button
                    key="close"
                    onClick={() => {
                        form.resetFields();
                        onClose();
                    }}
                >
                    Hủy
                </Button>
            ]}
            width={900}
        >
            <Form form={form} layout="vertical">
                <Form.Item
                    name="name"
                    label="Tên bãi đỗ"
                    rules={[{ required: true, message: 'Vui lòng nhập tên bãi đỗ!' }]}
                >
                    <Input />
                </Form.Item>

                <Form.Item
                    name="address"
                    label="Địa chỉ"
                    rules={[{ required: true, message: 'Vui lòng nhập địa chỉ!' }]}
                >
                    <Input />
                </Form.Item>

                <Form.Item
                    name="capacity"
                    label="Sức chứa"
                    rules={[
                        { required: true, message: 'Vui lòng nhập sức chứa!' },
                        { type: 'number', min: 1, message: 'Sức chứa phải lớn hơn 0!' }
                    ]}
                >
                    <InputNumber min={1} style={{ width: '100%' }} />
                </Form.Item>

                {isEditing && (
                    <Form.Item
                        name="availableSlots"
                        label="Chỗ trống"
                        rules={[
                            { required: true, message: 'Vui lòng nhập số chỗ trống!' },
                            { type: 'number', min: 0, message: 'Số chỗ trống không được âm!' }
                        ]}
                    >
                        <InputNumber min={0} style={{ width: '100%' }} />
                    </Form.Item>
                )}

                <Form.Item
                    name="operatingHours"
                    label="Giờ hoạt động"
                    rules={[{ required: true, message: 'Vui lòng nhập giờ hoạt động!' }]}
                >
                    <Select>
                        <Option value="24/7">24/7</Option>
                        <Option value="06:00-22:00">06:00-22:00</Option>
                        <Option value="07:00-22:00">07:00-22:00</Option>
                        <Option value="08:00-23:00">08:00-23:00</Option>
                        <Option value="09:00-24:00">09:00-24:00</Option>
                    </Select>
                </Form.Item>

                <Form.Item
                    name="hourlyRate"
                    label="Giá theo giờ (VNĐ)"
                    rules={[{ required: true, message: 'Vui lòng nhập giá theo giờ!' }]}
                >
                    <InputNumber
                        min={0}
                        style={{ width: '100%' }}
                        addonAfter="VNĐ"
                    />
                </Form.Item>

                <Form.Item
                    name="dailyRate"
                    label="Giá theo ngày (VNĐ)"
                    rules={[{ required: true, message: 'Vui lòng nhập giá theo ngày!' }]}
                >
                    <InputNumber
                        min={0}
                        style={{ width: '100%' }}
                        addonAfter="VNĐ"
                    />
                </Form.Item>

                <Form.Item
                    name="vehicleTypes"
                    label="Loại xe"
                    rules={[{ required: true, message: 'Vui lòng chọn loại xe!' }]}
                >
                    <Select
                        mode="multiple"
                        style={{ width: '100%' }}
                        placeholder="Chọn loại xe"
                    >
                        <Option value="Xe máy">Xe máy</Option>
                        <Option value="Ô tô">Ô tô</Option>
                        <Option value="Xe tải">Xe tải</Option>
                    </Select>
                </Form.Item>

                <Form.Item
                    name="isCovered"
                    label="Có mái che"
                    valuePropName="checked"
                >
                    <Switch />
                </Form.Item>

                <Form.Item
                    name="status"
                    label="Trạng thái"
                    rules={[{ required: true, message: 'Vui lòng chọn trạng thái!' }]}
                >
                    <Select>
                        <Option value="ACTIVE">Hoạt động</Option>
                        <Option value="INACTIVE">Ngừng hoạt động</Option>
                    </Select>
                </Form.Item>
            </Form>
        </Modal>
    );
};

export default CreateAndUpdateParkingLot;

import React, { useEffect, useState } from 'react';
import { Modal, Form, message, Button, Descriptions, Tag, Table, DatePicker, Tabs } from 'antd';
import { CreateParkingLotRequest, UpdateParkingLotRequest, useCreateParkingLotMutation, useUpdateParkingLotMutation, ParkingLot } from '../../../api/app_parkinglot/apiParkinglot';
import { useGetCurrentUserQuery } from '../../../api/app_home/apiAuth';
import { EditOutlined } from '@ant-design/icons';
import CreateAndUpdateParkingLot from './CreateAndUpdateParkingLot';
import { useGetEmployeeShiftByParkingLotIdQuery } from '../../../api/app_employee/apiEmployeeShifts';
import { useGetParkingEntriesByLotIdQuery, ParkingEntryResponse } from '../../../api/app_parking/apiParking';
import dayjs from 'dayjs';
import ParkingHistoryDetail from './ParkingHistoryDetail';
import { useAuth } from '../../../contexts/AuthContext';
import ParkingPlanManageTab from './ParkingPlanManageTab';

interface ParkingEntry {
    id: number;
    lotId: number;
    vehicleId: number;
    licensePlate: string;
    entryTime: string;
    exitTime: string | null;
    licensePlateImageEntry: string;
    licensePlateImageExit: string | null;
    status: string;
    totalCost: number | null;
    code: number;
}

interface ParkingLotDetailProps {
    visible: boolean;
    onClose: () => void;
    onSubmit: (values: CreateParkingLotRequest | UpdateParkingLotRequest) => Promise<void>;
    initialValues?: ParkingLot;
    isEditing: boolean;
}

const EmployeeShiftsTable: React.FC<{ parkingLotId: number }> = ({ parkingLotId }) => {
    const [selectedDate, setSelectedDate] = useState(dayjs());
    const { data: employeeShifts, isLoading } = useGetEmployeeShiftByParkingLotIdQuery(
        {
            parkingLotId: parkingLotId,
            workDate: selectedDate.format('YYYY-MM-DD')
        },
        {
            skip: !parkingLotId
        }
    );

    const columns = [
        {
            title: 'Nhân viên',
            dataIndex: 'employeeName',
            key: 'employeeName',
        },
        {
            title: 'Ca làm việc',
            dataIndex: 'shiftName',
            key: 'shiftName',
        },
        {
            title: 'Thời gian',
            dataIndex: 'shiftTime',
            key: 'shiftTime',
        },
        {
            title: 'Ngày trong tuần',
            dataIndex: 'dayOfWeek',
            key: 'dayOfWeek',
            render: (dayOfWeek: string) => {
                const dayConfig = {
                    MONDAY: { color: 'blue', label: 'Thứ hai' },
                    TUESDAY: { color: 'green', label: 'Thứ ba' },
                    WEDNESDAY: { color: 'purple', label: 'Thứ tư' },
                    THURSDAY: { color: 'orange', label: 'Thứ năm' },
                    FRIDAY: { color: 'red', label: 'Thứ sáu' },
                    SATURDAY: { color: 'cyan', label: 'Thứ bảy' },
                    SUNDAY: { color: 'magenta', label: 'Chủ nhật' }
                };

                const config = dayConfig[dayOfWeek as keyof typeof dayConfig] || { color: 'default', label: dayOfWeek };

                return (
                    <Tag color={config.color}>
                        {config.label}
                    </Tag>
                );
            }
        },
        {
            title: 'Trạng thái',
            dataIndex: 'status',
            key: 'status',
            render: (status: string) => {
                const statusConfig = {
                    SCHEDULED: { color: 'blue', label: 'Đã lên lịch' },
                    IN_PROGRESS: { color: 'processing', label: 'Đang thực hiện' },
                    COMPLETED: { color: 'green', label: 'Hoàn thành' },
                    ABSENT: { color: 'red', label: 'Vắng mặt' }
                };

                const config = statusConfig[status as keyof typeof statusConfig] || { color: 'default', label: status };

                return (
                    <Tag color={config.color}>
                        {config.label}
                    </Tag>
                );
            },
        },
    ];

    return (
        <div>
            <div style={{ marginBottom: 16 }}>
                <DatePicker
                    value={selectedDate}
                    onChange={(date) => date && setSelectedDate(date)}
                    style={{ width: 200 }}
                />
            </div>
            <Table
                columns={columns}
                dataSource={employeeShifts}
                rowKey="id"
                loading={isLoading}
            />
        </div>
    );
};

const ParkingHistoryTable: React.FC<{ parkingLotId: number }> = ({ parkingLotId }) => {
    const { data: parkingEntries, isLoading } = useGetParkingEntriesByLotIdQuery(parkingLotId);
    const [selectedEntry, setSelectedEntry] = useState<ParkingEntryResponse | null>(null);

    const columns = [
        {
            title: 'Mã xe',
            dataIndex: 'code',
            key: 'code',
        },
        {
            title: 'Biển số xe',
            dataIndex: 'licensePlate',
            key: 'licensePlate',
        },
        {
            title: 'Thời gian vào',
            dataIndex: 'entryTime',
            key: 'entryTime',
            render: (time: string) => dayjs(time).format('DD/MM/YYYY HH:mm:ss'),
        },
        {
            title: 'Thời gian ra',
            dataIndex: 'exitTime',
            key: 'exitTime',
            render: (time: string | null) => time ? dayjs(time).format('DD/MM/YYYY HH:mm:ss') : '-',
        },
        {
            title: 'Trạng thái',
            dataIndex: 'status',
            key: 'status',
            render: (status: string) => (
                <Tag color={status === 'ACTIVE' ? 'green' : 'blue'}>
                    {status === 'ACTIVE' ? 'Đang gửi' : 'Đã lấy'}
                </Tag>
            ),
        },
        {
            title: 'Chi phí',
            dataIndex: 'totalCost',
            key: 'totalCost',
            render: (cost: number | null) => cost ? `${cost.toLocaleString()} VNĐ` : '-',
        },
    ];

    // Kiểm tra và chuyển đổi dữ liệu
    const tableData = React.useMemo(() => {
        if (!parkingEntries) return [];
        if (Array.isArray(parkingEntries)) return parkingEntries;
        // Kiểm tra nếu dữ liệu nằm trong trường data
        const entries = parkingEntries as { data?: ParkingEntry[] };
        if (entries.data && Array.isArray(entries.data)) return entries.data;
        return [];
    }, [parkingEntries]);

    return (
        <>
            <Table
                columns={columns}
                dataSource={tableData}
                rowKey="id"
                scroll={{ y: 400 }}
                loading={isLoading}
                onRow={(record) => ({
                    onClick: () => setSelectedEntry(record),
                    style: { cursor: 'pointer' }
                })}
            />
            <ParkingHistoryDetail
                visible={!!selectedEntry}
                onClose={() => setSelectedEntry(null)}
                parkingEntry={selectedEntry}
            />
        </>
    );
};

const ParkingLotDetail: React.FC<ParkingLotDetailProps> = ({
    visible,
    onClose,
    onSubmit,
    initialValues,
    isEditing
}) => {
    const [form] = Form.useForm();
    const { data: userData } = useGetCurrentUserQuery();
    const [isEditMode, setIsEditMode] = useState(false);
    const { isAdmin } = useAuth();

    useEffect(() => {
        if (visible) {
            if (isEditing && initialValues) {
                form.setFieldsValue({
                    ...initialValues,
                    vehicleTypes: initialValues.vehicleTypes
                        .replace(/[\[\]]/g, '')
                        .split(',')
                });
                setIsEditMode(false);
            } else {
                form.resetFields();
                form.setFieldsValue({
                    status: 'ACTIVE',
                    isCovered: false
                });
                setIsEditMode(true);
            }
        }
    }, [visible, isEditing, initialValues, form]);

    const handleOk = async () => {
        try {
            const values = await form.validateFields();
            const formattedValues = {
                ...values,
                ownerId: userData?.data?.id,
                vehicleTypes: Array.isArray(values.vehicleTypes)
                    ? values.vehicleTypes.join(',')
                    : values.vehicleTypes
            };

            await onSubmit(formattedValues);
            form.resetFields();
            setIsEditMode(false);
        } catch (error) {
            console.error('Submission failed:', error);
            message.error('Có lỗi xảy ra. Vui lòng thử lại!');
        }
    };

    if (!isEditing || !initialValues) {
        return (
            <CreateAndUpdateParkingLot
                visible={visible}
                onClose={onClose}
                onSubmit={onSubmit}
                initialValues={undefined}
                isEditing={isEditing}
            />
        );
    }

    if (isEditMode) {
        return (
            <CreateAndUpdateParkingLot
                visible={visible}
                onClose={() => setIsEditMode(false)}
                onSubmit={onSubmit}
                initialValues={initialValues}
                isEditing={true}
            />
        );
    }

    const items = [
        {
            key: '1',
            label: 'Ca làm việc',
            children: <EmployeeShiftsTable parkingLotId={initialValues.id} />,
        },
        {
            key: '2',
            label: 'Lịch sử gửi xe',
            children: <ParkingHistoryTable parkingLotId={initialValues.id} />,
        },
        {
            key: '3',
            label: 'Danh sách gói',
            children: <ParkingPlanManageTab parkingLotId={initialValues.id} />,
        },
    ];

    return (
        <Modal
            title="Chi tiết bãi đỗ"
            open={visible}
            onCancel={onClose}
            footer={[
                isAdmin && (
                    <Button
                        key="edit"
                        type="primary"
                        icon={<EditOutlined />}
                        onClick={() => setIsEditMode(true)}
                    >
                        Sửa thông tin
                    </Button>
                ),
                <Button
                    key="close"
                    onClick={onClose}
                >
                    Đóng
                </Button>
            ]}
            width={1000}
        >
            <Descriptions bordered column={2}>
                <Descriptions.Item label="Tên bãi đỗ" span={2}>
                    {initialValues.name}
                </Descriptions.Item>
                <Descriptions.Item label="Địa chỉ" span={2}>
                    {initialValues.address}
                </Descriptions.Item>
                <Descriptions.Item label="Sức chứa">
                    {initialValues.capacity}
                </Descriptions.Item>
                <Descriptions.Item label="Chỗ trống">
                    {initialValues.availableSlots}
                </Descriptions.Item>
                <Descriptions.Item label="Giờ hoạt động">
                    {initialValues.operatingHours}
                </Descriptions.Item>
                <Descriptions.Item label="Có mái che">
                    {initialValues.isCovered ? 'Có' : 'Không'}
                </Descriptions.Item>
                <Descriptions.Item label="Giá theo giờ">
                    {initialValues.hourlyRate.toLocaleString()} VNĐ
                </Descriptions.Item>
                <Descriptions.Item label="Giá theo ngày">
                    {initialValues.dailyRate.toLocaleString()} VNĐ
                </Descriptions.Item>
                <Descriptions.Item label="Loại xe" span={2}>
                    {initialValues.vehicleTypes
                        .replace(/[\[\]]/g, '')
                        .split(',')
                        .map((type: string, index: number) => (
                            <Tag color="blue" key={index} style={{ margin: '2px' }}>
                                {type.trim()}
                            </Tag>
                        ))}
                </Descriptions.Item>
                <Descriptions.Item label="Trạng thái">
                    <Tag color={initialValues.status === 'ACTIVE' ? 'green' : 'red'}>
                        {initialValues.status === 'ACTIVE' ? 'Hoạt động' : 'Ngừng hoạt động'}
                    </Tag>
                </Descriptions.Item>
            </Descriptions>

            <div style={{ marginTop: 24 }}>
                <Tabs defaultActiveKey="1" items={items} />
            </div>
        </Modal>
    );
};

export default ParkingLotDetail;

import React, { useState } from 'react';
import {
    Button,
    Table,
    Tag,
    Progress,
    message,
    Input,
    Select,
    Row,
    Col,
    Card,
    Typography,
    Space,
    Popconfirm
} from 'antd';
import type { ColumnsType } from 'antd/es/table';
import {
    PlusOutlined,
    SearchOutlined,
    EditOutlined,
    DeleteOutlined,
    EnvironmentOutlined,
    CarOutlined,
    InfoCircleOutlined
} from '@ant-design/icons';
import { useAuth } from '../../../contexts/AuthContext';
import { useDebounce } from '../../../hooks/useDebounce';
import {
    useGetAllParkingLotsQuery,
    useCreateParkingLotMutation,
    useUpdateParkingLotMutation,
    ParkingLot,
    useDeleteParkingLotMutation,
    ParkingLotFilter
} from '../../../api/app_parkinglot/apiParkinglot';
import ParkingLotDetail from './ParkingLotDetail';
import './ParkingLotManageTab.css';
const { Text } = Typography;

const ParkingLotManageTab: React.FC = () => {
    const { user, isAdmin } = useAuth();
    const [filters, setFilters] = useState<ParkingLotFilter>({});
    const [searchValue, setSearchValue] = useState<string>('');
    const debouncedSearchValue = useDebounce(searchValue, 500);
    const { data: parkingLotsData, isLoading, refetch } = useGetAllParkingLotsQuery({
        ...filters,
        name: debouncedSearchValue
    });
    const [createParkingLot] = useCreateParkingLotMutation();
    const [updateParkingLot] = useUpdateParkingLotMutation();
    const [deleteParkingLot] = useDeleteParkingLotMutation();
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedParking, setSelectedParking] = useState<ParkingLot | undefined>(undefined);
    const [isEdit, setIsEdit] = useState(false);

    const handleFilterChange = (key: keyof ParkingLotFilter, value: string | string[] | boolean | undefined) => {
        setFilters(prev => {
            const newFilters = { ...prev };
            if (key === 'vehicleTypes') {
                if (value && Array.isArray(value) && value.length > 0) {
                    newFilters[key] = value.join(',');
                } else {
                    delete newFilters[key];
                }
            } else if (key === 'isCovered') {
                if (typeof value === 'boolean') {
                    newFilters[key] = value;
                } else {
                    delete newFilters[key];
                }
            } else {
                if (value) {
                    newFilters[key] = value as string;
                } else {
                    delete newFilters[key];
                }
            }
            return newFilters;
        });
    };

    const handleDeleteParking = async (record: ParkingLot) => {
        try {
            await deleteParkingLot(record.id).unwrap();
            message.success('Xóa bãi đỗ thành công!');
            refetch();
        } catch (error) {
            message.error('Có lỗi xảy ra khi xóa bãi đỗ!');
        }
    };

    const columns: ColumnsType<ParkingLot> = [
        {
            title: 'TÊN BÃI ĐỖ',
            dataIndex: 'name',
            key: 'name',
            render: (text: string, record: ParkingLot) => (
                <div className="parking-name-cell">
                    <div className="parking-name">{text}</div>
                    <div className="parking-address">
                        <EnvironmentOutlined className="address-icon" />
                        <Text type="secondary">{record.address}</Text>
                    </div>
                </div>
            ),
        },
        {
            title: 'LOẠI XE',
            dataIndex: 'vehicleTypes',
            key: 'vehicleTypes',
            render: (vehicleTypes: string) => (
                <div className="vehicle-tags">
                    {vehicleTypes
                        .replace(/[\[\]]/g, '')
                        .split(',')
                        .map((type, index) => (
                            <Tag
                                key={index}
                                color={type.includes('Xe máy') ? 'blue' : type.includes('Ô tô') ? 'geekblue' : 'cyan'}
                                className="vehicle-tag"
                            >
                                {type.trim()}
                            </Tag>
                        ))}
                </div>
            )
        },
        {
            title: 'SỨC CHỨA',
            dataIndex: 'capacity',
            key: 'capacity',
            align: 'center',
            render: (value) => <Text strong>{value}</Text>
        },
        {
            title: 'CHỖ TRỐNG',
            dataIndex: 'availableSlots',
            key: 'availableSlots',
            align: 'center',
            render: (value, record) => (
                <div className={`available-slots ${value < 5 ? 'low-availability' : ''}`}>
                    <Text strong>{value}</Text>
                    {value < 5 && <InfoCircleOutlined className="warning-icon" />}
                </div>
            )
        },
        {
            title: 'TÌNH TRẠNG',
            key: 'occupancy',
            render: (_, record) => (
                <div className="occupancy-container">
                    <Progress
                        percent={Math.round((record.availableSlots / record.capacity) * 100)}
                        status={record.availableSlots === 0 ? 'exception' : 'normal'}
                        strokeColor={record.availableSlots / record.capacity > 0.3 ? '#52c41a' : '#faad14'}
                        showInfo={false}
                    />
                    <Text type="secondary" className="occupancy-text">
                        {Math.round((record.availableSlots / record.capacity) * 100)}% còn trống
                    </Text>
                </div>
            )
        },
        {
            title: 'GIÁ CẢ',
            key: 'pricing',
            render: (_, record) => (
                <div className="pricing-info">
                    <div className="pricing-item">
                        <Text type="secondary">Giờ:</Text>
                        <Text strong className="pricing-value">{record.hourlyRate.toLocaleString()}đ</Text>
                    </div>
                    <div className="pricing-item">
                        <Text type="secondary">Ngày:</Text>
                        <Text strong className="pricing-value">{record.dailyRate.toLocaleString()}đ</Text>
                    </div>
                </div>
            )
        },
        {
            title: 'TRẠNG THÁI',
            dataIndex: 'status',
            key: 'status',
            render: (status) => (
                <Tag
                    color={status === 'ACTIVE' ? 'green' : 'red'}
                    className="status-tag"
                >
                    {status === 'ACTIVE' ? 'HOẠT ĐỘNG' : 'NGỪNG HOẠT ĐỘNG'}
                </Tag>
            )
        },
        ...(isAdmin ? [{
            title: 'HÀNH ĐỘNG',
            key: 'action',
            align: 'center' as const,
            render: (_, record) => (
                <Space size="small">
                    <Button
                        type="primary"
                        ghost
                        icon={<EditOutlined />}
                        onClick={(e) => {
                            e.stopPropagation();
                            handleEditParking(record);
                        }}
                        className="action-button"
                    />
                    <Popconfirm
                        title="Xác nhận xóa bãi đỗ"
                        description="Bạn có chắc chắn muốn xóa bãi đỗ này?"
                        onConfirm={(e) => {
                            e?.stopPropagation();
                            handleDeleteParking(record);
                        }}
                        onCancel={(e) => e?.stopPropagation()}
                        okText="Xóa"
                        cancelText="Hủy"
                        placement="topRight"
                    >
                        <Button
                            danger
                            icon={<DeleteOutlined />}
                            onClick={(e) => e.stopPropagation()}
                            className="action-button"
                        />
                    </Popconfirm>
                </Space>
            )
        }] : [])
    ];

    const handleAddParking = () => {
        setSelectedParking(undefined);
        setIsModalOpen(true);
        setIsEdit(false);
    };

    const handleEditParking = (record: ParkingLot) => {
        setSelectedParking(record);
        setIsModalOpen(true);
        setIsEdit(true);
    };

    const handleSubmit = async (values: any) => {
        try {
            if (!user?.id) {
                message.error('Không tìm thấy thông tin người dùng');
                return;
            }

            if (isEdit && selectedParking) {
                await updateParkingLot({
                    id: selectedParking.id,
                    data: values
                }).unwrap();
                message.success('Cập nhật bãi đỗ thành công!');
            } else {
                await createParkingLot({
                    ...values,
                    ownerId: user.id,
                    availableSlots: values.availableSlots || values.capacity
                }).unwrap();
                message.success('Thêm bãi đỗ thành công!');
            }
            setIsModalOpen(false);
            refetch();
        } catch (error) {
            message.error('Có lỗi xảy ra. Vui lòng thử lại!');
        }
    };

    return (
        <div className="parking-lot-manage">
            <Card className="filter-card">
                <Row gutter={[16, 16]} align="middle">
                    <Col xs={24} md={6}>
                        <Input
                            placeholder="Tìm kiếm theo tên"
                            prefix={<SearchOutlined />}
                            value={searchValue}
                            onChange={e => setSearchValue(e.target.value)}
                            allowClear
                            size="large"
                        />
                    </Col>
                    <Col xs={24} md={6}>
                        <Select
                            mode="multiple"
                            placeholder="Loại xe"
                            style={{ width: '100%' }}
                            value={filters.vehicleTypes ? filters.vehicleTypes.split(',') : undefined}
                            onChange={value => handleFilterChange('vehicleTypes', value)}
                            allowClear
                            size="large"
                            suffixIcon={<CarOutlined />}
                        >
                            <Select.Option value="Xe máy">Xe máy</Select.Option>
                            <Select.Option value="Ô tô">Ô tô</Select.Option>
                            <Select.Option value="Xe tải">Xe tải</Select.Option>
                            <Select.Option value="Xe đạp">Xe đạp</Select.Option>
                        </Select>
                    </Col>
                    <Col xs={24} md={4}>
                        <Select
                            placeholder="Mái che"
                            style={{ width: '100%' }}
                            value={filters.isCovered}
                            onChange={value => handleFilterChange('isCovered', value)}
                            allowClear
                            size="large"
                        >
                            <Select.Option value={true}>Có mái che</Select.Option>
                            <Select.Option value={false}>Không mái che</Select.Option>
                        </Select>
                    </Col>
                    <Col xs={24} md={4}>
                        <Select
                            placeholder="Trạng thái"
                            style={{ width: '100%' }}
                            value={filters.status}
                            onChange={value => handleFilterChange('status', value)}
                            allowClear
                            size="large"
                        >
                            <Select.Option value="ACTIVE">Hoạt động</Select.Option>
                            <Select.Option value="INACTIVE">Ngừng hoạt động</Select.Option>
                        </Select>
                    </Col>
                    {isAdmin && (
                        <Col xs={24} md={4} style={{ textAlign: 'right' }}>
                            <Button
                                type="primary"
                                icon={<PlusOutlined />}
                                onClick={handleAddParking}
                                size="large"
                                className="add-button"
                            >
                                Thêm bãi đỗ
                            </Button>
                        </Col>
                    )}
                </Row>
            </Card>

            <Card className="table-card">
                <Table
                    columns={columns}
                    dataSource={parkingLotsData}
                    rowKey="id"
                    loading={isLoading}
                    rowClassName={() => 'parking-row hover:cursor-default'}
                    pagination={{
                        pageSize: 8,
                        showSizeChanger: false,
                        showTotal: (total) => `Tổng ${total} bãi đỗ`
                    }}
                    scroll={{ x: 1200 }}
                />
            </Card>

            <ParkingLotDetail
                visible={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                onSubmit={handleSubmit}
                initialValues={selectedParking}
                isEditing={isEdit}
            />
        </div>
    );
};

export default ParkingLotManageTab;

import React, { useState } from 'react';
import { Table, Button, Modal, Form, Input, InputNumber, Switch, message, Popconfirm, Select, Space } from 'antd';
import { PlusOutlined, EditOutlined, DeleteOutlined } from '@ant-design/icons';
import {
    useGetAllParkingPlansQuery,
    useCreateParkingPlanMutation,
    useUpdateParkingPlanMutation,
    useDeleteParkingPlanMutation,
    ParkingPlan
} from '../../../api/app_parkingPlan/apiParkingPlan';

interface ParkingPlanManageTabProps {
    parkingLotId: number;
}

const ParkingPlanManageTab: React.FC<ParkingPlanManageTabProps> = ({ parkingLotId }) => {
    const { data: parkingPlans = [], isLoading, refetch } = useGetAllParkingPlansQuery({ parkingLotId });
    const [createParkingPlan, { isLoading: isCreating }] = useCreateParkingPlanMutation();
    const [updateParkingPlan, { isLoading: isUpdating }] = useUpdateParkingPlanMutation();
    const [deleteParkingPlan, { isLoading: isDeleting }] = useDeleteParkingPlanMutation();

    const [isModalVisible, setIsModalVisible] = useState(false);
    const [editingPlan, setEditingPlan] = useState<ParkingPlan | null>(null);
    const [form] = Form.useForm();

    const lotPlans = Array.isArray(parkingPlans) ? parkingPlans : (parkingPlans as any)?.data || [];

    const handleAdd = () => {
        setEditingPlan(null);
        form.resetFields();
        form.setFieldsValue({
            parkingLotId: parkingLotId,
            priceUnit: 'MONTH',
            isActive: true
        });
        setIsModalVisible(true);
    };

    const handleEdit = (record: ParkingPlan) => {
        setEditingPlan(record);
        form.setFieldsValue({
            ...record,
            priceUnit: record.priceUnit,
        });
        setIsModalVisible(true);
    };

    const handleDelete = async (id: number) => {
        try {
            await deleteParkingPlan(id).unwrap();
            message.success('Xóa gói thành công!');
            refetch();
        } catch (error) {
            message.error('Có lỗi xảy ra khi xóa!');
        }
    };

    const handleOk = async () => {
        try {
            const values = await form.validateFields();
            const payload = { ...values, parkingLotId: parkingLotId };

            if (editingPlan) {
                await updateParkingPlan({ id: editingPlan.id, data: payload }).unwrap();
                message.success('Cập nhật gói thành công!');
            } else {
                await createParkingPlan(payload).unwrap();
                message.success('Thêm gói mới thành công!');
            }
            setIsModalVisible(false);
            refetch();
        } catch (error) {
            message.error('Có lỗi xảy ra!');
        }
    };

    const columns = [
        {
            title: 'Tên gói',
            dataIndex: 'name',
            key: 'name',
        },
        {
            title: 'Giá',
            dataIndex: 'price',
            key: 'price',
            render: (val: number, record: any) => `${new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(val)} / ${record.priceUnit}`,
        },
        {
            title: 'Loại gói',
            dataIndex: 'planType',
            key: 'planType',
        },
        {
            title: 'Mô tả',
            dataIndex: 'description',
            key: 'description',
            ellipsis: true,
        },
        {
            title: 'Phổ biến',
            dataIndex: 'isPopular',
            key: 'isPopular',
            render: (val: boolean) => val ? 'Có' : 'Không',
        },
        {
            title: 'Hành động',
            key: 'action',
            render: (_: any, record: ParkingPlan) => (
                <Space>
                    <Button icon={<EditOutlined />} onClick={() => handleEdit(record)} />
                    <Popconfirm title="Bạn có chắc chắn muốn xóa?" onConfirm={() => handleDelete(record.id)}>
                        <Button icon={<DeleteOutlined />} danger />
                    </Popconfirm>
                </Space>
            ),
        },
    ];

    return (
        <div className="mt-4">
            <Button type="primary" icon={<PlusOutlined />} onClick={handleAdd} className="mb-4">
                Thêm gói mới
            </Button>
            <Table
                dataSource={lotPlans}
                columns={columns}
                rowKey="id"
                loading={isLoading}
                pagination={{ pageSize: 5 }}
            />

            <Modal
                title={editingPlan ? "Cập nhật gói" : "Thêm gói mới"}
                open={isModalVisible}
                onOk={handleOk}
                onCancel={() => setIsModalVisible(false)}
                confirmLoading={isCreating || isUpdating}
                width={800}
            >
                <Form form={form} layout="vertical">
                    <Form.Item name="name" label="Tên gói" rules={[{ required: true }]}>
                        <Input />
                    </Form.Item>

                    <Form.Item name="parkingLotId" hidden>
                        <InputNumber />
                    </Form.Item>

                    <div className="grid grid-cols-2 gap-4">
                        <Form.Item name="price" label="Giá (VND)" rules={[{ required: true }]}>
                            <InputNumber style={{ width: '100%' }} />
                        </Form.Item>
                        <Form.Item name="priceUnit" label="Chu kỳ" rules={[{ required: true }]}>
                            <Select>
                                <Select.Option value="DAY">Ngày</Select.Option>
                                <Select.Option value="MONTH">Tháng</Select.Option>
                                <Select.Option value="YEAR">Năm</Select.Option>
                            </Select>
                        </Form.Item>
                        <Form.Item name="planType" label="Loại gói (VD: STANDARD, PREMIUM)" rules={[{ required: true }]}>
                            <Input />
                        </Form.Item>

                    </div>
                    <Form.Item name="description" label="Mô tả">
                        <Input.TextArea rows={2} />
                    </Form.Item>

                    <div className="grid grid-cols-2 md:grid-cols-3 gap-4 bg-gray-50 p-4 rounded-lg">
                        <Form.Item name="isUnlimitedParking" valuePropName="checked" label="Đỗ xe không giới hạn">
                            <Switch />
                        </Form.Item>
                        <Form.Item name="hasFixedSpot" valuePropName="checked" label="Chỗ cố định">
                            <Switch />
                        </Form.Item>
                        <Form.Item name="hasValetService" valuePropName="checked" label="Valet Parking">
                            <Switch />
                        </Form.Item>
                        <Form.Item name="hasCarWash" valuePropName="checked" label="Rửa xe miễn phí">
                            <Switch />
                        </Form.Item>
                        <Form.Item name="hasCoveredParking" valuePropName="checked" label="Có mái che">
                            <Switch />
                        </Form.Item>
                        <Form.Item name="hasSecurity247" valuePropName="checked" label="An ninh 24/7">
                            <Switch />
                        </Form.Item>
                    </div>

                    <div className="grid grid-cols-2 gap-4 mt-4">
                        <Form.Item name="isPopular" valuePropName="checked" label="Gói Phổ biến">
                            <Switch />
                        </Form.Item>
                        <Form.Item name="isActive" valuePropName="checked" label="Đang hoạt động">
                            <Switch />
                        </Form.Item>
                    </div>
                </Form>
            </Modal>
        </div>
    );
};

export default ParkingPlanManageTab;

import React from 'react';
import { Modal, Descriptions, Tag } from 'antd';
import { useGetAttendanceByIdQuery, Attendance } from '../../../api/app_employee/apiAttendance';
import dayjs from 'dayjs';

interface AttendanceDetailsModalProps {
    attendanceId: string | null;
    isOpen: boolean;
    onClose: () => void;
}

const AttendanceDetailsModal: React.FC<AttendanceDetailsModalProps> = ({
    attendanceId,
    isOpen,
    onClose,
}) => {
    const { data: attendance, isLoading } = useGetAttendanceByIdQuery(attendanceId || '', {
        skip: !attendanceId
    });

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'PRESENT':
                return 'success';
            case 'ABSENT':
                return 'error';
            case 'LATE':
                return 'warning';
            case 'EARLY':
                return 'warning';
            default:
                return 'default';
        }
    };

    const getStatusText = (status: string) => {
        switch (status) {
            case 'PRESENT':
                return 'Có mặt';
            case 'ABSENT':
                return 'Vắng mặt';
            case 'LATE':
                return 'Đi muộn';
            case 'EARLY':
                return 'Về sớm';
            default:
                return status;
        }
    };

    return (
        <Modal
            title="Chi tiết chấm công"
            open={isOpen}
            onCancel={onClose}
            footer={null}
            width={600}
        >
            {isLoading ? (
                <div>Đang tải...</div>
            ) : attendance ? (
                <Descriptions bordered column={1}>
                    <Descriptions.Item label="Nhân viên">{attendance.employeeName}</Descriptions.Item>
                    <Descriptions.Item label="Giờ vào ca">
                        {attendance.checkInTime ? dayjs(attendance.checkInTime).format('DD/MM/YYYY HH:mm:ss') : '-'}
                    </Descriptions.Item>
                    <Descriptions.Item label="Giờ ra ca">
                        {attendance.checkOutTime ? dayjs(attendance.checkOutTime).format('DD/MM/YYYY HH:mm:ss') : '-'}
                    </Descriptions.Item>
                    <Descriptions.Item label="Trạng thái">
                        <Tag color={getStatusColor(attendance.status)}>
                            {getStatusText(attendance.status)}
                        </Tag>
                    </Descriptions.Item>
                </Descriptions>
            ) : (
                <div>Không tìm thấy thông tin chấm công</div>
            )}
        </Modal>
    );
};

export default AttendanceDetailsModal;
